    {"name": "Žanjice Beach", "municipality_slug": "herceg-novi", "category_slug": "plaze", "lat": 42.3933, "lng": 18.5689, "short_description": "Popular pebble beach on the Luštica peninsula, accessible by boat or car. Crystal clear water and nearby Blue Grotto.", "long_description": "Žanjice is the premier beach on the Luštica Peninsula, featuring white pebbles and turquoise waters in a sheltered bay. The beach serves as the main gateway to the famous Blue Cave (Plava Špilja), with boat trips departing regularly from the shore. Accessible by car via the Luštica road or by water taxi from Herceg Novi. Sun lounger and umbrella rental is available, along with several beach restaurants serving fresh seafood. Parking is available above the beach but fills quickly in peak season - arriving before 10 AM is recommended.", "beach_type": "pebble", "featured": True, "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 90, "tags": ["beach", "swimming", "boat-access"], "amenities": ["sunbed-rental", "restaurant", "bar", "boat-trips", "parking", "snorkeling"], "best_for": ["swimming", "snorkeling", "day-trip"], "accessibility_notes": None, "source_url": "https://www.hercegnovi.travel/en/beaches", "source_type": "curated"},
    {"name": "Mirište Beach", "municipality_slug": "herceg-novi", "category_slug": "plaze", "lat": 42.3897, "lng": 18.5641, "short_description": "Secluded pebble beach near Žanjice, surrounded by lush Mediterranean vegetation.", "long_description": "Mirište is a secluded pebble beach just around the headland from Žanjice, surrounded by lush Mediterranean vegetation that provides natural shade. The beach is less crowded than its neighbor and retains a more peaceful atmosphere. Access is via a short walking path from Žanjice or directly by boat. The clear water is excellent for snorkeling around the rocky edges. Basic refreshments are available from a small seasonal beach bar.", "beach_type": "pebble", "family_friendly": True, "hidden_gem": True, "parking_available": False, "pet_friendly": False, "popularity_score": 70, "tags": ["beach", "secluded", "nature"], "amenities": ["seasonal-bar", "natural-shade", "snorkeling"], "best_for": ["swimming", "snorkeling", "tranquility"], "accessibility_notes": None, "source_url": "https://www.hercegnovi.travel/en/beaches", "source_type": "curated"},
    {"name": "Savina Beach", "municipality_slug": "herceg-novi", "category_slug": "plaze", "lat": 42.4553, "lng": 18.5378, "short_description": "Small pebble beach near the Savina Monastery. Calm waters ideal for families.", "long_description": "A small, family-friendly pebble beach located near the beautiful Savina Monastery complex. The calm, sheltered waters of the inner bay make it ideal for young children. The nearby monastery (dating to the 11th century) with its precious icons and lush gardens provides a cultural complement to the beach visit. A small beach bar operates in summer. The beach is within walking distance of several Savina restaurants.", "beach_type": "pebble", "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 60, "amenities": ["beach-bar", "calm-water", "monastery-nearby"], "best_for": ["families", "swimming"], "accessibility_notes": None, "source_url": "https://www.hercegnovi.travel/en/beaches", "source_type": "curated"},
    {"name": "Igalo Riviera", "municipality_slug": "herceg-novi", "category_slug": "plaze", "lat": 42.4571, "lng": 18.5101, "short_description": "Long promenade beach in Igalo, known for therapeutic mud and mineral springs. Home to the Institute Dr Simo Milošević.", "long_description": "Igalo's beach stretches along a pleasant promenade in the westernmost part of Herceg Novi, renowned for its therapeutic mud and mineral springs. The Institute Dr Simo Milošević, a major rehabilitation center, sits along the beach and has attracted wellness visitors for decades. The sandy bottom and shallow water (especially near Tito's Villa at the far end) make it one of the best family beaches in the bay. Numerous cafes, restaurants, and ice cream shops line the promenade. The beach area is flat and fully accessible.", "beach_type": "sandy", "family_friendly": True, "featured": True, "parking_available": True, "pet_friendly": False, "popularity_score": 80, "tags": ["wellness", "promenade", "therapeutic"], "amenities": ["promenade", "cafes", "restaurants", "therapeutic-mud", "mineral-springs", "flat-access", "shallow-water"], "best_for": ["families", "wellness", "swimming"], "accessibility_notes": "Flat promenade with direct beach access. One of the most accessible beaches in Montenegro.", "source_url": "https://www.hercegnovi.travel/en/beaches", "source_type": "curated"},
    {"name": "Blue Grotto (Plava Špilja)", "municipality_slug": "herceg-novi", "category_slug": "plaze", "lat": 42.3889, "lng": 18.5594, "short_description": "Natural sea cave near Žanjice with stunning blue light effects. Accessible by boat.", "long_description": "The Blue Grotto is a natural sea cave near Žanjice where sunlight refracts through the underwater entrance creating stunning blue light effects on the cave walls and water. Accessible only by boat, tours depart regularly from Herceg Novi, Žanjice, and other bay locations. The best time to visit is in the morning when sunlight creates the most vivid blue glow. Swimming inside the cave is permitted and unforgettable. Boat tours typically combine the Blue Grotto with stops at nearby beaches. Speedboat tours cost approximately 25-40 EUR.", "featured": True, "parking_available": False, "pet_friendly": False, "popularity_score": 85, "tags": ["cave", "boat-trip", "nature"], "amenities": ["boat-access", "swimming-in-cave"], "best_for": ["boat-tour", "photography"], "accessibility_notes": None, "source_url": "https://www.hercegnovi.travel/en/attractions", "source_type": "curated"},
