    {"name": "Kanli Kula Fortress", "municipality_slug": "herceg-novi", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.4531, "lng": 18.5372, "short_description": "Ottoman-era fortress and open-air theatre overlooking the bay. Hosts summer film and theatre festivals.", "long_description": "Built by the Ottoman Turks in 1539 and expanded by the Venetians in 1687, Kanli Kula (meaning 'Bloody Tower') served as a prison during Ottoman rule. Today the massive fortress has been transformed into an atmospheric open-air amphitheater hosting summer film screenings, theatre performances, and cultural festivals. The fortress offers commanding views over the Bay of Kotor and the old town below. A small entrance fee applies. The steep climb up from the old town is rewarded with spectacular panoramas.", "featured": True, "cultural_site": True, "parking_available": False, "pet_friendly": False, "popularity_score": 85, "tags": ["fortress", "ottoman", "theatre"], "amenities": ["amphitheater", "cultural-events", "panoramic-views"], "best_for": ["history", "cultural-events", "photography"], "accessibility_notes": "Steep climb with many steps. Not wheelchair accessible.", "source_url": "https://www.hercegnovi.travel/en/fortresses", "source_type": "curated"},
    {"name": "Forte Mare", "municipality_slug": "herceg-novi", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.4523, "lng": 18.5383, "short_description": "Seaside fortress at the entrance to the old town. Built in the 14th century, now a venue for cultural events.", "long_description": "Forte Mare guards the entrance to Herceg Novi's old town from the sea side, built in the 14th century and subsequently modified by each power that controlled the city. Today it serves as a venue for cultural events, art exhibitions, and summer concerts. The fortress includes a sea-level swimming platform popular with locals and an upper terrace with panoramic views. Small entrance fee for the upper fortress. One of the most photographed buildings in Herceg Novi.", "featured": True, "cultural_site": True, "parking_available": False, "pet_friendly": False, "popularity_score": 80, "tags": ["fortress", "medieval", "seaside"], "amenities": ["cultural-events", "swimming-platform", "exhibitions"], "best_for": ["history", "photography", "swimming"], "accessibility_notes": None, "source_url": "https://www.hercegnovi.travel/en/fortresses", "source_type": "curated"},
    {"name": "Španjola Fortress", "municipality_slug": "herceg-novi", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.4537, "lng": 18.5390, "short_description": "Spanish-built fortress on the hill above the old town. Panoramic views of the entire Bay of Kotor.", "long_description": "The Spanish Fortress sits at the highest point above Herceg Novi's old town, built during the brief Spanish occupation in the early 16th century. The climb up through the old town's narrow streets and stone staircases is steep but rewarding - the fortress offers the most comprehensive panoramic views in the city, encompassing the entire Bay of Kotor, the open sea, and the surrounding mountains. Currently undergoing intermittent restoration, check locally for access status.", "cultural_site": True, "parking_available": False, "pet_friendly": False, "popularity_score": 70, "tags": ["fortress", "panorama", "spanish"], "amenities": ["panoramic-views"], "best_for": ["photography", "panoramic-views"], "accessibility_notes": "Very steep climb through old town. Not accessible for mobility-impaired visitors.", "source_url": "https://www.hercegnovi.travel/en/fortresses", "source_type": "curated"},
    # Monasteries & Churches
    {"name": "Savina Monastery", "municipality_slug": "herceg-novi", "category_slug": "manastiri-crkve", "lat": 42.4544, "lng": 18.5403, "short_description": "Serbian Orthodox monastery complex dating to the 11th century, set in lush gardens overlooking the bay. Houses precious icons and manuscripts.", "long_description": "The Savina Monastery is one of the most important Serbian Orthodox religious sites on the Adriatic, comprising a complex of churches dating from the 11th to 18th centuries set in magnificent Mediterranean gardens. The Small Church (11th century) contains medieval frescoes, while the Large Church (18th century) houses the precious Savina icon and valuable manuscripts. The monastery's lush botanical gardens cascade down the hillside toward the bay, offering peaceful walks among exotic plants. Free entry; modest dress required.", "featured": True, "cultural_site": True, "parking_available": True, "pet_friendly": False, "popularity_score": 90, "tags": ["monastery", "orthodox", "medieval"], "amenities": ["gardens", "museum", "free-entry"], "best_for": ["history", "culture", "photography"], "accessibility_notes": "Hillside location with steps. Lower church accessible, upper areas require climbing.", "source_url": "https://www.hercegnovi.travel/en/monasteries-and-churches", "source_type": "curated"},
    # Nature
    {"name": "Herceg Novi Botanical Garden", "municipality_slug": "herceg-novi", "category_slug": "priroda-vidikovci", "lat": 42.4520, "lng": 18.5365, "short_description": "Mediterranean botanical garden with subtropical and tropical plants. Terraced gardens with bay views.", "long_description": "This terraced Mediterranean garden above the old town features an impressive collection of subtropical and tropical plants, many brought by Herceg Novi's seafaring merchants over centuries. The garden cascades down the hillside in a series of terraces, each offering different plant species and bay views. Mimosa trees bloom spectacularly in February, and the garden is at its most colorful in spring. The peaceful atmosphere provides a welcome retreat from the summer heat. Small entrance fee.", "family_friendly": True, "parking_available": False, "pet_friendly": False, "popularity_score": 65, "tags": ["garden", "botany", "nature"], "amenities": ["terraced-paths", "bay-views", "shade"], "best_for": ["nature", "photography", "relaxation"], "accessibility_notes": None, "source_url": "https://www.hercegnovi.travel/en/nature", "source_type": "curated"},

