    {"name": "Kotor Old Town", "municipality_slug": "kotor", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.4247, "lng": 18.7712, "short_description": "UNESCO World Heritage medieval walled town. Labyrinth of narrow streets, Romanesque churches, and Venetian palaces at the head of the bay.", "long_description": "Kotor's UNESCO-listed medieval walled town is one of the best-preserved medieval cities in the Mediterranean. Enter through the main Sea Gate (Vrata od Mora) to discover a labyrinth of narrow cobblestone streets, Romanesque churches, Venetian palaces, and charming squares. Key sights include St. Tryphon Cathedral, the Maritime Museum, Clock Tower, and numerous churches. The famous Kotor cats appear on every corner, with a dedicated Cat Museum. The town fills with cruise ship visitors during the day (10 AM - 4 PM); early morning and evening visits offer a more intimate experience.", "featured": True, "cultural_site": True, "parking_available": True, "pet_friendly": True, "popularity_score": 100, "tags": ["unesco", "medieval", "venetian", "old-town"], "amenities": ["restaurants", "shops", "museums", "churches", "tourist-info"], "best_for": ["sightseeing", "history", "photography"], "accessibility_notes": "Cobblestone streets throughout. Mostly flat inside the walls but uneven surfaces. Main gates are accessible.", "source_url": "https://kotor.travel/en/attractions", "source_type": "curated"},
    {"name": "Kotor Fortress (San Giovanni)", "municipality_slug": "kotor", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.4268, "lng": 18.7742, "short_description": "Fortified walls climbing 1200 meters to the Castle of San Giovanni. 1350 steps with breathtaking views of Boka Bay.", "long_description": "The fortifications climb 1,200 meters from the old town to the Castle of San Giovanni at 280 meters elevation, requiring approximately 1,350 steps. The climb takes 45-90 minutes depending on fitness. Multiple viewpoints along the route offer increasingly dramatic panoramas of Boka Bay. Entrance fee is charged at the old town trailhead (free if starting from the Ladder of Kotor at the back). Bring plenty of water, wear proper shoes, and avoid climbing during midday heat. The Church of Our Lady of Health provides a rest stop partway up.", "featured": True, "cultural_site": True, "active_holiday": True, "parking_available": True, "pet_friendly": False, "popularity_score": 95, "tags": ["fortress", "hiking", "panorama", "medieval"], "amenities": ["viewpoints", "church-midway"], "best_for": ["hiking", "photography", "sunset"], "accessibility_notes": "1,350 stone steps. Not accessible for mobility-impaired visitors. Requires good physical condition.", "source_url": "https://kotor.travel/en/attractions", "source_type": "curated"},
    {"name": "Cathedral of Saint Tryphon", "municipality_slug": "kotor", "category_slug": "manastiri-crkve", "lat": 42.4247, "lng": 18.7713, "short_description": "Romanesque cathedral built in 1166, the most prominent building in Kotor's old town. Contains precious relics and medieval frescoes.", "long_description": "Kotor's most iconic building, the Romanesque Cathedral of Saint Tryphon was first built in 1166 and reconstructed after earthquakes. The twin bell towers (not matching due to earthquake damage) are Kotor's most recognizable silhouette. Inside, 14th-century frescoes, a medieval ciborium (canopy over the altar), and the treasury containing Saint Tryphon's relics and golden religious objects await visitors. The cathedral is an active place of worship; entrance fee for tourists with modest dress required.", "featured": True, "cultural_site": True, "parking_available": True, "pet_friendly": False, "popularity_score": 90, "tags": ["cathedral", "romanesque", "medieval"], "amenities": ["guided-tours", "treasury"], "best_for": ["history", "culture", "architecture"], "accessibility_notes": None, "source_url": "https://kotor.travel/en/culture-and-history", "source_type": "curated"},
    # Kotor area places
    {"name": "Perast", "municipality_slug": "kotor", "category_slug": "znamenitosti", "lat": 42.4869, "lng": 18.6978, "short_description": "Tiny baroque town on the Bay of Kotor, with 16 churches and 17 palaces. Starting point for boats to Our Lady of the Rocks.", "long_description": "Perast is a tiny baroque jewel on the Bay of Kotor with 16 churches and 17 palaces - remarkable for a town that never had more than a few hundred residents. The Venetian-era palaces line the waterfront, and the town serves as the departure point for boats to Our Lady of the Rocks island (5 EUR round trip, 5 minutes). The Perast Museum in the Bujović Palace documents the town's distinguished naval history. Visit early morning or late afternoon to avoid day-trip crowds. Free to walk around; small fees for museum and island church.", "featured": True, "cultural_site": True, "parking_available": True, "pet_friendly": True, "popularity_score": 95, "tags": ["baroque", "venetian", "bay"], "amenities": ["museum", "boat-trips", "restaurants", "waterfront-promenade"], "best_for": ["sightseeing", "boat-trip", "photography"], "accessibility_notes": None, "source_url": "https://kotor.travel/en/attractions", "source_type": "curated"},
    {"name": "Our Lady of the Rocks", "municipality_slug": "kotor", "category_slug": "znamenitosti", "lat": 42.4870, "lng": 18.6885, "short_description": "Man-made island with a 15th-century church, created by locals who threw rocks into the sea over centuries. Museum with Tripo Kokolja paintings.", "long_description": "This man-made island was created over centuries by local sailors who followed a tradition of dropping a rock in the sea upon each safe return. The 15th-century Church of Our Lady of the Rocks contains 68 paintings by 17th-century Baroque artist Tripo Kokolja, silver votive tablets from grateful sailors, and a fascinating tapestry woven over 25 years by a local woman using gold thread and her own hair. The small museum charges a modest entrance fee. Boats depart every 30 minutes from Perast's waterfront (5 EUR return).", "featured": True, "cultural_site": True, "parking_available": False, "pet_friendly": False, "popularity_score": 95, "tags": ["island", "church", "museum", "unique"], "amenities": ["museum", "church", "boat-access"], "best_for": ["history", "culture", "boat-trip"], "accessibility_notes": None, "source_url": "https://kotor.travel/en/attractions", "source_type": "curated"},
    {"name": "Maritime Museum of Montenegro", "municipality_slug": "kotor", "category_slug": "muzeji-kultura", "lat": 42.4248, "lng": 18.7708, "short_description": "Museum housed in a baroque palace in Kotor's old town, documenting the rich maritime history of Boka Bay.", "long_description": "Housed in the Grgurina Palace, a baroque building in the heart of Kotor's old town, the Maritime Museum chronicles the rich seafaring history of Boka Bay through three floors of exhibits. Collections include ship models, naval uniforms, navigational instruments, weapons, and portraits of famous Bay captains. The museum provides essential context for understanding why this small bay produced some of the Mediterranean's greatest sailors. Allow 1-2 hours for a thorough visit.", "cultural_site": True, "parking_available": True, "pet_friendly": False, "popularity_score": 70, "tags": ["museum", "maritime", "history"], "amenities": ["exhibits", "gift-shop"], "best_for": ["history", "culture", "rainy-day"], "accessibility_notes": None, "source_url": "https://kotor.travel/en/culture-and-history", "source_type": "curated"},
    # Beaches
    {"name": "Bajova Kula Beach", "municipality_slug": "kotor", "category_slug": "plaze", "lat": 42.4230, "lng": 18.7680, "short_description": "Small beach just outside Kotor's old town walls. Convenient location with views of the fortifications.", "long_description": "A small but convenient pebble beach located just outside Kotor's old town walls, offering views of the medieval fortifications rising above. The beach has basic facilities including sun lounger rental and a seasonal cafe. Its proximity to the old town makes it the easiest swimming option for visitors staying in Kotor center. The water is calm and clean, though the beach gets busy when cruise ships are in port.", "beach_type": "pebble", "parking_available": True, "pet_friendly": False, "popularity_score": 60, "family_friendly": True, "amenities": ["sunbed-rental", "cafe", "old-town-proximity"], "best_for": ["swimming", "convenience"], "accessibility_notes": None, "source_url": "https://kotor.travel/en/beaches", "source_type": "curated"},
    {"name": "Morinj Beach", "municipality_slug": "kotor", "category_slug": "plaze", "lat": 42.4894, "lng": 18.6528, "short_description": "Quiet pebble beach in the village of Morinj, Bay of Kotor. Known for its restaurants and the freshwater Sopot waterfall nearby.", "long_description": "Quiet pebble beach in the village of Morinj on the inner part of Boka Bay. The area is known for the freshwater Sopot waterfall that flows into the bay nearby, creating interesting temperature variations in the swimming water. Several excellent restaurants (including the renowned Ćatovića Mlini) make Morinj an ideal destination for combining beach time with a memorable meal. The village is peaceful and authentically Montenegrin, with stone houses and Mediterranean vegetation.", "beach_type": "pebble", "hidden_gem": True, "parking_available": True, "pet_friendly": True, "popularity_score": 55, "amenities": ["restaurants", "waterfall-nearby", "parking"], "best_for": ["swimming", "dining", "tranquility"], "accessibility_notes": None, "source_url": "https://kotor.travel/en/beaches", "source_type": "curated"},
    # Nature
    {"name": "Vrmac Ridge Trail", "municipality_slug": "kotor", "category_slug": "priroda-vidikovci", "lat": 42.4400, "lng": 18.7400, "short_description": "Mountain ridge trail between Kotor and Tivat offering panoramic views of both bays. Old Austrian fort at the summit.", "long_description": "The Vrmac Ridge offers a mountain hiking experience between Kotor and Tivat, with panoramic views of both bays from the summit of Saint Ilija peak (760m). The main trail starts at Trojica pass and follows the ridge through Mediterranean scrubland and past old Austrian fortifications. Fort Vrmac at 480m provides a dramatic rest stop with views. The full ridge walk takes 4-6 hours, but shorter sections are possible. Mountain biking tours also use these trails. Bring water, sun protection, and proper hiking shoes.", "active_holiday": True, "parking_available": True, "pet_friendly": True, "popularity_score": 75, "tags": ["hiking", "trail", "panorama"], "amenities": ["marked-trails", "fort-viewpoint"], "best_for": ["hiking", "panoramic-views", "fitness"], "accessibility_notes": None, "source_url": "https://kotor.travel/en/nature", "source_type": "curated"},
    {"name": "Ladder of Kotor (Kotor Serpentines)", "municipality_slug": "kotor", "category_slug": "priroda-vidikovci", "lat": 42.4300, "lng": 18.7750, "short_description": "Ancient zigzag trail climbing from Kotor to the village of Krstac, with stunning views at every turn. Historic mule path.", "long_description": "This ancient zigzag mule path climbs from behind Kotor's old town to the village of Krstac at approximately 800 meters elevation, offering stunning views at every switchback. Originally a trade route, the stone-paved path is one of the most photogenic hikes in Montenegro. The climb takes 2-3 hours up and provides a free alternative route to the Kotor Fortress (entering from above rather than paying at the bottom). Best attempted in early morning to avoid heat. The path connects to the Vrmac Ridge for extended hikes.", "active_holiday": True, "featured": True, "parking_available": True, "pet_friendly": True, "popularity_score": 80, "tags": ["hiking", "historic-trail", "panorama"], "amenities": ["marked-path", "viewpoints"], "best_for": ["hiking", "photography", "fitness"], "accessibility_notes": "Steep zigzag trail with 800m elevation gain. Requires good fitness. Not accessible for mobility-impaired visitors.", "source_url": "https://kotor.travel/en/nature", "source_type": "curated"},

    # ==================== TIVAT ====================
    {"name": "Porto Montenegro", "municipality_slug": "tivat", "category_slug": "znamenitosti", "lat": 42.4351, "lng": 18.6916, "short_description": "Luxury superyacht marina and waterfront village built on a former naval base. Shops, restaurants, and the Naval Heritage Collection museum.", "long_description": "Built on the site of the former Yugoslav Navy arsenal, Porto Montenegro is a luxury superyacht marina and lifestyle village that has transformed Tivat. The complex features 450 berths accommodating yachts up to 250 meters, designer boutiques, international restaurants, a pool club, and the Naval Heritage Collection museum. The waterfront promenade is free to walk and offers excellent people-watching. Events include yacht shows, regattas, and fashion events throughout the season. The marina village has become the social hub of the bay.", "featured": True, "parking_available": True, "pet_friendly": True, "popularity_score": 90, "tags": ["marina", "luxury", "shopping", "dining"], "amenities": ["restaurants", "shops", "marina", "pool-club", "museum", "events"], "best_for": ["dining", "shopping", "nightlife"], "accessibility_notes": None, "source_url": "https://tivat.travel/en/attractions", "source_type": "curated"},
    {"name": "Island of Flowers (Miholjska Prevlaka)", "municipality_slug": "tivat", "category_slug": "priroda-vidikovci", "lat": 42.4115, "lng": 18.6826, "short_description": "Small peninsula with a botanical garden, connected to the mainland by a short bridge. Medieval monastery ruins and diverse plant species.", "long_description": "Miholjska Prevlaka, locally called the Island of Flowers, is a small peninsula connected to the mainland by a short bridge, about 2 km south of Tivat center. The site contains ruins of a medieval Benedictine monastery, diverse Mediterranean and exotic plant species, and peaceful walking paths. The botanical diversity includes palms, cypresses, and flowering plants from around the world. The flat paths are suitable for families with strollers. Free entry. The island offers views across the bay toward Herceg Novi.", "featured": True, "family_friendly": True, "parking_available": True, "pet_friendly": True, "popularity_score": 80, "tags": ["island", "garden", "monastery", "nature"], "amenities": ["walking-paths", "botanical-gardens", "monastery-ruins", "free-entry", "bay-views"], "best_for": ["nature", "families", "photography"], "accessibility_notes": None, "source_url": "https://tivat.travel/en/nature", "source_type": "curated"},
    {"name": "Plavi Horizonti Beach", "municipality_slug": "tivat", "category_slug": "plaze", "lat": 42.3786, "lng": 18.6853, "short_description": "One of the most beautiful sandy beaches in the Bay of Kotor, on the Luštica peninsula. Shallow water, ideal for families.", "long_description": "Often ranked as the best beach in the Bay of Kotor, Plavi Horizonti (Blue Horizons) is a 350-meter sandy beach in Pržno bay on the Luštica peninsula. The shallow, crystal-clear water warms quickly in summer, making it ideal for young children. The beach is backed by olive and pine groves providing natural shade. Sun loungers and umbrellas are available for rent, and a beach bar serves drinks and snacks. Parking is available but limited; arriving before 10 AM in summer is essential. The beach is about 15 minutes by car from Tivat.", "beach_type": "sandy", "featured": True, "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 90, "tags": ["sandy-beach", "family", "calm-water"], "amenities": ["sunbed-rental", "beach-bar", "natural-shade", "parking", "showers", "changing-rooms"], "best_for": ["families", "swimming", "relaxation"], "accessibility_notes": None, "source_url": "https://tivat.travel/en/beaches", "source_type": "curated"},
    {"name": "Donja Lastva Beach", "municipality_slug": "tivat", "category_slug": "plaze", "lat": 42.4167, "lng": 18.6833, "short_description": "Small pebbly beach in a charming historic village near Tivat. Quiet and less crowded.", "long_description": "A small pebbly beach in the charming historic village of Donja Lastva, just south of Tivat center. The village retains its traditional stone architecture and quiet atmosphere despite proximity to Porto Montenegro. The beach is less crowded than Tivat's main beaches and offers a glimpse of authentic bay life. Several cafes in the village serve coffee and snacks. The old stone church and village square are worth exploring after your swim.", "beach_type": "pebble", "family_friendly": True, "hidden_gem": True, "parking_available": True, "pet_friendly": True, "popularity_score": 50, "amenities": ["cafes", "village-charm"], "best_for": ["swimming", "tranquility", "local-experience"], "accessibility_notes": None, "source_url": "https://tivat.travel/en/beaches", "source_type": "curated"},
    {"name": "Ponta Beach", "municipality_slug": "tivat", "category_slug": "plaze", "lat": 42.4381, "lng": 18.6945, "short_description": "City beach right next to Porto Montenegro. Easy access, good facilities, and close to restaurants.", "long_description": "Tivat's main city beach located right next to Porto Montenegro, Ponta offers the most convenient swimming option in town. The pebble beach has full facilities including sun lounger rental, showers, changing rooms, and is within steps of Porto Montenegro's restaurants and cafes. The shallow gradient makes it suitable for families. The beach gets busy during peak season but the adjacent marina village provides plenty of shade and refreshment options.", "beach_type": "pebble", "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 65, "amenities": ["sunbed-rental", "showers", "changing-rooms", "restaurants-nearby"], "best_for": ["swimming", "convenience", "families"], "accessibility_notes": None, "source_url": "https://tivat.travel/en/beaches", "source_type": "curated"},
    {"name": "Naval Heritage Collection", "municipality_slug": "tivat", "category_slug": "muzeji-kultura", "lat": 42.4355, "lng": 18.6920, "short_description": "Museum inside Porto Montenegro documenting the history of the Yugoslav Navy and the Tivat naval base.", "long_description": "Located inside Porto Montenegro, this museum documents the fascinating history of the Yugoslav Navy and the Tivat naval base that preceded the luxury marina. Exhibits include a preserved submarine (the P-821 Hero), torpedo boats, naval weapons, uniforms, and historical photographs documenting the transformation from military base to superyacht marina. The submarine tour is a highlight, especially for families with children. Allow 1-2 hours for a full visit. Small entrance fee.", "cultural_site": True, "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 55, "amenities": ["submarine-tour", "exhibits", "gift-shop", "air-conditioning"], "best_for": ["history", "families", "rainy-day"], "accessibility_notes": None, "source_url": "https://tivat.travel/en/culture", "source_type": "curated"},
    {"name": "Big City Park (Veliki Gradski Park)", "municipality_slug": "tivat", "category_slug": "priroda-vidikovci", "lat": 42.4340, "lng": 18.6950, "short_description": "Large waterfront park in Tivat with diverse Mediterranean and exotic plant species, walking paths, and bay views.", "long_description": "Tivat's central waterfront park spans a large area along the bay, featuring diverse Mediterranean and exotic plant species, well-maintained walking paths, and numerous benches with bay views. The park connects the city center to Porto Montenegro via a pleasant promenade. Children's playgrounds, a seasonal outdoor cafe, and regular cultural events make it a gathering point for families. The flat, paved paths are fully accessible. Free entry.", "family_friendly": True, "parking_available": True, "pet_friendly": True, "popularity_score": 60, "tags": ["park", "nature", "waterfront"], "amenities": ["playground", "cafes", "walking-paths", "benches", "bay-views", "flat-paths"], "best_for": ["families", "walking", "relaxation"], "accessibility_notes": "Fully accessible with paved flat paths throughout.", "source_url": "https://tivat.travel/en/nature", "source_type": "curated"},

    # ==================== BUDVA ====================
    {"name": "Budva Old Town (Stari Grad)", "municipality_slug": "budva", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.2889, "lng": 18.8381, "short_description": "2500-year-old walled Mediterranean town on a small peninsula. Narrow cobblestone streets, churches, citadela fortress, and seaside promenades.", "long_description": "Budva's 2,500-year-old walled old town sits on a small peninsula jutting into the Adriatic. Within the medieval walls, narrow cobblestone streets wind between Venetian-era houses, past ancient churches (including the 9th-century Santa Maria in Punta and 7th-century St. John), art galleries, and buzzing restaurants and bars. The Citadela fortress at the southern tip offers rooftop panoramic views. By day the old town fills with tourists; by night it transforms into Montenegro's most vibrant dining and nightlife district. Free to enter; Citadela charges a small fee.", "featured": True, "cultural_site": True, "parking_available": True, "pet_friendly": True, "popularity_score": 95, "tags": ["old-town", "medieval", "nightlife", "dining"], "amenities": ["restaurants", "bars", "shops", "galleries", "citadela", "nightlife"], "best_for": ["sightseeing", "nightlife", "dining"], "accessibility_notes": None, "source_url": "https://budva.travel/en/attractions", "source_type": "curated"},
    {"name": "Sveti Stefan", "municipality_slug": "budva", "category_slug": "znamenitosti", "lat": 42.2575, "lng": 18.8908, "short_description": "Iconic fortified island village connected to the mainland by a narrow isthmus. Former fishing village, now an exclusive Aman resort. Photographable from the beach.", "long_description": "Sveti Stefan is Montenegro's most iconic landmark - a fortified island village connected to the mainland by a narrow sandy isthmus. Once a 15th-century fishing village, it was converted into an exclusive resort in the 1960s (hosted Marilyn Monroe, Sophia Loren) and is now operated by Aman Resorts. Non-guests cannot access the island, but the public beach on the southern side of the isthmus offers perfect views for photography. The viewpoint from the road above, especially at sunset, is one of the most photographed spots in the Balkans.", "featured": True, "parking_available": True, "pet_friendly": False, "popularity_score": 100, "tags": ["island", "iconic", "luxury", "photography"], "amenities": ["public-beach", "viewpoint", "photography"], "best_for": ["photography", "beach", "luxury"], "accessibility_notes": None, "source_url": "https://budva.travel/en/attractions", "source_type": "curated"},
    {"name": "Mogren Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2908, "lng": 18.8331, "short_description": "Two connected pebble beaches west of the old town, accessed through a cliff tunnel. Beautiful setting between rocky cliffs.", "long_description": "Two connected pebble beaches west of Budva's old town, accessed through a dramatic cliff tunnel carved through the rock. Mogren I (closer to town) has sun lounger rental and a beach bar. Mogren II (further) has an inflatable aqua park and more space. The beaches sit between towering rocky cliffs with Mediterranean vegetation above, creating a dramatic natural amphitheater. The dancer statue at the entrance is a popular photo spot. Access is via a 10-minute walk along a scenic cliffside path from the old town.", "beach_type": "pebble", "featured": True, "parking_available": False, "pet_friendly": False, "popularity_score": 85, "tags": ["scenic", "cliff", "tunnel"], "amenities": ["sunbed-rental", "beach-bar", "aqua-park", "showers"], "best_for": ["swimming", "scenery"], "accessibility_notes": None, "source_url": "https://budva.travel/en/beaches", "source_type": "curated"},
    {"name": "Slovenska Plaza", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2869, "lng": 18.8419, "short_description": "The main city beach of Budva, stretching 1600 meters. Full facilities, water sports, and lively beach bars.", "long_description": "Budva's main city beach stretches 1,600 meters along the waterfront east of the old town. The beach is divided into numerous sections, some free and some managed with sun lounger rental. A continuous strip of beach bars, restaurants, and shops lines the promenade behind the beach. Water sports including jet skiing, parasailing, and banana boats are available. The beach is most crowded during July-August when it's the social epicenter of Montenegrin summer tourism. Water taxi boats depart for Sveti Nikola island.", "beach_type": "pebble", "featured": True, "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 80, "tags": ["city-beach", "facilities", "water-sports"], "amenities": ["sunbed-rental", "restaurants", "beach-bars", "water-sports", "water-taxi", "showers", "changing-rooms"], "best_for": ["swimming", "water-sports", "socializing"], "accessibility_notes": None, "source_url": "https://budva.travel/en/beaches", "source_type": "curated"},
    {"name": "Jaz Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2978, "lng": 18.8089, "short_description": "Large beach (1200m) west of Budva, famous for hosting major music festivals. Mix of sand and pebble sections.", "long_description": "One of Montenegro's most famous beaches, Jaz stretches 1,200 meters in a wide bay west of Budva. The beach has two sections: a larger mixed sand-and-pebble section and a smaller nudist section behind a rocky outcrop. Jaz has hosted major music festivals including Sea Dance Festival (Best European Festival award). The beach has car parking (5 EUR in season), sun lounger rental, beach bars, and restaurants. A freshwater river creates a lagoon at the eastern end. Jaz is popular with both tourists and Budva locals on weekends.", "beach_type": "mixed", "featured": True, "parking_available": True, "pet_friendly": False, "popularity_score": 85, "tags": ["festival", "large-beach", "music"], "amenities": ["parking", "sunbed-rental", "beach-bars", "restaurants", "water-sports", "festival-venue"], "best_for": ["festivals", "groups", "swimming"], "accessibility_notes": None, "source_url": "https://budva.travel/en/beaches", "source_type": "curated"},
    {"name": "Bečići Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2808, "lng": 18.8542, "short_description": "Long sandy beach that once won the Grand Prix in Paris for the most beautiful beach in Europe. Excellent facilities.", "long_description": "This long sandy beach famously won the Grand Prix in Paris in 1935 for the most beautiful beach in Europe. The fine golden sand stretches nearly 2 km along a sweeping bay backed by major resort hotels. Full facilities include sun lounger rental, water sports, beach bars, and restaurants. The Mediteran hotel's aqua park provides an additional family attraction. Bečići connects seamlessly to Budva via a tunnel and to Rafailovići along the beach. The beach offers excellent conditions for families with gradually shelving sand.", "beach_type": "sandy", "featured": True, "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 90, "tags": ["award-winning", "sandy", "resort"], "amenities": ["sunbed-rental", "water-sports", "beach-bars", "restaurants", "aqua-park-nearby", "showers", "lifeguard"], "best_for": ["families", "swimming", "water-sports"], "accessibility_notes": None, "source_url": "https://budva.travel/en/beaches", "source_type": "curated"},
    {"name": "Kamenovo Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2753, "lng": 18.8583, "short_description": "Scenic pebble beach between Bečići and Rafailovići. Sheltered cove with pine trees and clear water.", "long_description": "A scenic pebble beach in a sheltered cove between Bečići and Rafailovići, framed by pine trees and rocky cliffs. The clear water is excellent for snorkeling, and the pine trees provide natural shade. A beach bar and restaurant operate in season. Access is via a steep staircase from the road above (approximately 100 steps). The beach is quieter than Bečići and Slovenska, offering a more relaxed atmosphere. Parking is available along the road above.", "beach_type": "pebble", "parking_available": True, "pet_friendly": False, "popularity_score": 70, "tags": ["cove", "scenic", "pine-trees"], "amenities": ["beach-bar", "restaurant", "natural-shade", "snorkeling"], "best_for": ["swimming", "snorkeling", "relaxation"], "accessibility_notes": "Approximately 100 steep steps to reach beach. Not wheelchair accessible.", "source_url": "https://budva.travel/en/beaches", "source_type": "curated"},
    {"name": "Sveti Stefan Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2578, "lng": 18.8890, "short_description": "Pink-pebble beach facing the iconic Sveti Stefan island. Southern section is public, northern is for Aman guests.", "long_description": "The beach flanking the iconic Sveti Stefan island isthmus features distinctive pink pebbles that glow warmly in the afternoon sun. The beach is divided: the southern/public section is freely accessible (sun lounger rental available), while the northern section is reserved exclusively for Aman Resort guests. The public section offers unobstructed views of the medieval island village. The beach is one of the most photographed in the Mediterranean. A cafe at the entrance serves drinks and light meals.", "beach_type": "pebble", "featured": True, "parking_available": True, "pet_friendly": False, "popularity_score": 90, "tags": ["iconic", "pink-pebble", "scenic"], "amenities": ["sunbed-rental", "cafe", "photography-spot"], "best_for": ["photography", "swimming", "scenery"], "accessibility_notes": None, "source_url": "https://budva.travel/en/beaches", "source_type": "curated"},
    {"name": "Ploče Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2781, "lng": 18.8600, "short_description": "Modern beach club with concrete platforms, pools, and a trendy atmosphere. Popular with younger visitors.", "long_description": "Ploče is not a traditional beach but a modern beach club complex with concrete platforms, swimming pools, and a trendy atmosphere. Multiple levels cascade down to the sea, with pools at different heights and direct sea access. The venue is popular with younger visitors seeking a party atmosphere and Instagram-worthy setting. Entrance fee includes use of the pools. DJs play during summer afternoons and evenings. The beach club also serves food and cocktails. Located between Bečići and Kamenovo.", "beach_type": "rocky", "nightlife": True, "parking_available": True, "pet_friendly": False, "popularity_score": 75, "tags": ["beach-club", "pools", "trendy"], "amenities": ["pools", "dj", "restaurant", "bar", "changing-rooms", "showers"], "best_for": ["party", "swimming", "socializing"], "accessibility_notes": None, "source_url": "https://budva.travel/en/beaches", "source_type": "curated"},
    {"name": "Citadela Budva", "municipality_slug": "budva", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.2886, "lng": 18.8375, "short_description": "Medieval citadel at the southern tip of Budva's old town. Houses a library and offers panoramic rooftop views.", "long_description": "The medieval citadel occupies the southern tip of Budva's old town peninsula, offering the highest vantage point within the walls. Built between the 9th and 15th centuries, the fortress now houses a small library and hosts cultural events in its courtyard. The rooftop terrace provides 360-degree panoramic views encompassing the old town, Slovenska Plaža, Sveti Nikola island, and the open Adriatic. A small entrance fee is charged. The citadel's stone walls and sea views make it one of the best sunset spots in Budva.", "cultural_site": True, "featured": True, "parking_available": True, "pet_friendly": False, "popularity_score": 80, "tags": ["fortress", "panorama", "medieval"], "amenities": ["panoramic-views", "library", "cultural-events"], "best_for": ["photography", "sunset", "history"], "accessibility_notes": None, "source_url": "https://budva.travel/en/fortresses", "source_type": "curated"},
    {"name": "Church of Santa Maria in Punta", "municipality_slug": "budva", "category_slug": "manastiri-crkve", "lat": 42.2891, "lng": 18.8381, "short_description": "9th-century church within the old town walls, one of the oldest sacred buildings on the Adriatic coast.", "long_description": "This 9th-century church within Budva's old town walls is one of the oldest sacred buildings on the Adriatic coast. The simple Romanesque architecture, with its stone walls and modest interior, contrasts with the ornate later churches of the region. The church occasionally hosts classical music concerts and art exhibitions due to its excellent acoustics. Located near the Citadela at the tip of the old town peninsula, it's easy to visit as part of an old town walk.", "cultural_site": True, "parking_available": True, "pet_friendly": False, "popularity_score": 55, "amenities": ["concert-venue", "exhibitions"], "best_for": ["history", "culture", "architecture"], "accessibility_notes": None, "source_url": "https://budva.travel/en/churches-and-monasteries", "source_type": "curated"},

    # ==================== BAR ====================
    {"name": "Stari Bar (Old Bar)", "municipality_slug": "bar", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.0906, "lng": 19.1308, "short_description": "Impressive medieval fortress city ruins on a hillside 4km from the coast. Over 240 buildings, an aqueduct, churches, and hamam ruins dating to the 6th century.", "long_description": "Stari Bar (Old Bar) is one of the most impressive archaeological sites on the Montenegrin coast - a vast medieval fortress city with over 240 buildings spread across a rocky hillside 4 km from modern Bar. Dating from the 6th century, the ruins include churches, mosques, a Turkish bath (hamam), an aqueduct, and residential buildings reflecting centuries of diverse rule. A small museum at the entrance displays artifacts and provides context. The surrounding olive groves include trees over 2,000 years old. Allow 2-3 hours for thorough exploration. Entrance fee approximately 3 EUR.", "featured": True, "cultural_site": True, "parking_available": True, "pet_friendly": True, "popularity_score": 90, "tags": ["ruins", "medieval", "fortress", "archaeological"], "amenities": ["museum", "guided-tours", "souvenir-shop", "parking"], "best_for": ["history", "photography", "exploration"], "accessibility_notes": None, "source_url": "https://bar.travel/en/attractions", "source_type": "curated"},
    {"name": "Old Olive Tree of Bar", "municipality_slug": "bar", "category_slug": "znamenitosti", "lat": 42.0836, "lng": 19.1122, "short_description": "One of the oldest olive trees in the world, estimated to be over 2000 years old. A symbol of Bar and a protected natural monument.", "long_description": "The Old Olive Tree of Bar is estimated to be over 2,000 years old, making it one of the oldest living trees in Europe and a symbol of the city of Bar. Located in the village of Mirovica between modern Bar and Stari Bar, the tree has a circumference of over 10 meters and still produces olives. A small fence protects the tree, and an information board tells its history. Traditionally, local couples circle the tree before their wedding for good luck. Free to visit; a small olive-themed souvenir shop operates nearby.", "featured": True, "parking_available": True, "pet_friendly": True, "popularity_score": 80, "tags": ["nature", "ancient", "olive-tree", "unique"], "amenities": ["information-board", "souvenir-shop", "free-entry"], "best_for": ["history", "nature", "photography"], "accessibility_notes": "Accessible via a short, mostly flat path from the road.", "source_url": "https://bar.travel/en/attractions", "source_type": "curated"},
    {"name": "Bar Promenade (King Nikola's Palace)", "municipality_slug": "bar", "category_slug": "znamenitosti", "lat": 42.0939, "lng": 19.1000, "short_description": "Seafront promenade area with King Nikola's Palace (now a museum), botanical garden, and the palace chapel.", "long_description": "Bar's seafront area centers on King Nikola's Palace, built in 1885, which now houses the local museum with collections of historical artifacts, traditional costumes, and paintings. The surrounding botanical garden features rare plant species collected by the royal family. The palace chapel hosts occasional concerts. The adjacent waterfront promenade extends along the marina, lined with cafes and restaurants. The area is flat and pleasant for walking, connecting the city center with the port area.", "cultural_site": True, "parking_available": True, "pet_friendly": True, "popularity_score": 65, "tags": ["palace", "museum", "promenade"], "amenities": ["museum", "botanical-garden", "chapel", "promenade", "cafes"], "best_for": ["history", "walking", "culture"], "accessibility_notes": "Flat waterfront promenade. Museum has ground-floor access.", "source_url": "https://bar.travel/en/attractions", "source_type": "curated"},
    {"name": "Sutomore Beach", "municipality_slug": "bar", "category_slug": "plaze", "lat": 42.1439, "lng": 19.0417, "short_description": "Long sandy beach in the resort town of Sutomore. One of the most popular family beaches on the Montenegrin coast.", "long_description": "Sutomore is one of Montenegro's most popular family beach resorts, featuring a long golden sandy beach backed by pine forests. The resort has a lively summer atmosphere with numerous beach bars, cafes, and restaurants along the promenade. Water sports including jet skiing and banana boats are available. Sutomore is connected to Bar and Podgorica by train (station within walking distance of the beach), making it one of the most accessible beaches in Montenegro. Accommodation options range from hotels to apartments.", "beach_type": "sandy", "featured": True, "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 80, "tags": ["sandy", "family", "resort"], "amenities": ["beach-bars", "restaurants", "water-sports", "train-station", "sunbed-rental", "showers"], "best_for": ["families", "swimming", "water-sports"], "accessibility_notes": None, "source_url": "https://bar.travel/en/beaches", "source_type": "curated"},
    {"name": "Žukotrlica Beach", "municipality_slug": "bar", "category_slug": "plaze", "lat": 42.0778, "lng": 19.0953, "short_description": "Quiet beach south of Bar, known for its clean water and pebbly shores. Less crowded than city beaches.", "long_description": "A quiet pebble beach south of Bar center, known for its exceptionally clean water and lack of crowds. The beach is less developed than the resort beaches, offering a more natural swimming experience. A few small seasonal cafes serve refreshments. The beach is accessible by car or bus from Bar, with limited parking available nearby. Good snorkeling conditions along the rocky edges.", "beach_type": "pebble", "hidden_gem": True, "parking_available": True, "pet_friendly": True, "popularity_score": 50, "amenities": ["seasonal-cafes", "parking"], "best_for": ["swimming", "snorkeling", "tranquility"], "accessibility_notes": None, "source_url": "https://bar.travel/en/beaches", "source_type": "curated"},
    {"name": "Čanj Beach", "municipality_slug": "bar", "category_slug": "plaze", "lat": 42.1553, "lng": 19.0194, "short_description": "Sandy beach in the small resort of Čanj. Calm sea, good for families with children.", "long_description": "A sandy beach in the small resort of Čanj, located between Sutomore and Petrovac. The beach is known for its calm sea conditions and family-friendly atmosphere, with gradually shelving sand that's safe for children. Several mini-markets, restaurants, and cafes serve the resort. The quieter atmosphere compared to Sutomore and Budva makes Čanj popular with families seeking a more relaxed holiday. Parking available at the resort.", "beach_type": "sandy", "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 60, "amenities": ["restaurants", "mini-markets", "parking", "sunbed-rental"], "best_for": ["families", "swimming", "relaxation"], "accessibility_notes": None, "source_url": "https://bar.travel/en/beaches", "source_type": "curated"},
    {"name": "Red Beach (Crvena Plaža)", "municipality_slug": "bar", "category_slug": "plaze", "lat": 42.1100, "lng": 19.0750, "short_description": "Distinctive beach with reddish pebbles and sand, surrounded by red-tinted cliffs. Unique geological formation.", "long_description": "Red Beach gets its name from the distinctive reddish pebbles and sand derived from the surrounding red-tinted cliffs, creating a unique geological spectacle. The beach is relatively small and less visited, making it ideal for those seeking a unique, uncrowded swimming experience. The unusual color creates striking photographs, especially during golden hour. Access requires a short walk from the nearest road. No commercial facilities on the beach itself.", "beach_type": "pebble", "hidden_gem": True, "parking_available": True, "pet_friendly": True, "popularity_score": 55, "tags": ["unique", "red-sand", "geological"], "amenities": [], "best_for": ["photography", "swimming", "tranquility"], "accessibility_notes": None, "source_url": "https://bar.travel/en/beaches", "source_type": "curated"},
    {"name": "Haj-Nehaj Fortress", "municipality_slug": "bar", "category_slug": "tvrdjave-stari-gradovi", "lat": 42.1422, "lng": 19.0478, "short_description": "15th-century hilltop fortress above Sutomore with panoramic views of the coast. Unique for having both a church and a mosque.", "long_description": "Perched on a hilltop above Sutomore at approximately 200 meters elevation, Haj-Nehaj is a 15th-century fortress remarkable for containing both a church and a mosque within its walls - reflecting the region's layered religious history. The climb from Sutomore takes about 30-40 minutes through Mediterranean scrubland and offers increasingly spectacular panoramic views of the coast, islands, and mountains. The fortress walls are well-preserved, and you can walk the perimeter. Free entry. Best visited in early morning or late afternoon.", "cultural_site": True, "parking_available": True, "pet_friendly": True, "popularity_score": 60, "tags": ["fortress", "hilltop", "panorama"], "amenities": ["panoramic-views", "free-entry"], "best_for": ["hiking", "history", "photography"], "accessibility_notes": "Steep 30-40 minute hike required. Not accessible for mobility-impaired visitors.", "source_url": "https://bar.travel/en/attractions", "source_type": "curated"},

    # ==================== ULCINJ ====================
    {"name": "Velika Plaža (Long Beach)", "municipality_slug": "ulcinj", "category_slug": "plaze", "lat": 41.9256, "lng": 19.2175, "short_description": "13km stretch of sandy beach, one of the longest on the Adriatic. Known for its dark mineral-rich sand, kitesurfing, and beach bars.", "long_description": "At 13 kilometers, Velika Plaža (Long Beach) is one of the longest sandy beaches on the entire Adriatic coast. The dark, mineral-rich sand is believed to have therapeutic properties. The beach is divided into sections, some with full amenities (sunbeds, bars, restaurants) and others completely wild and empty. The northern end near town has the most facilities, while conditions become progressively wilder toward Ada Bojana in the south. Reliable thermal winds from May to September make it one of the Mediterranean's premier kitesurfing destinations. Multiple kite schools operate along the beach.", "beach_type": "sandy", "featured": True, "parking_available": True, "pet_friendly": True, "popularity_score": 95, "tags": ["long-beach", "sandy", "kitesurfing", "iconic"], "amenities": ["sunbed-rental", "beach-bars", "restaurants", "kitesurfing-schools", "parking", "showers"], "best_for": ["kitesurfing", "beach-walks", "water-sports"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/beaches", "source_type": "curated"},
    {"name": "Ada Bojana", "municipality_slug": "ulcinj", "category_slug": "plaze", "lat": 41.8714, "lng": 19.2853, "short_description": "River island at the border with Albania, famous for its natural nudist beach, fresh fish restaurants, and windsurfing conditions.", "long_description": "Ada Bojana is a triangular river island at the confluence of the Bojana River and the Adriatic, straddling the border with Albania. The island is famous for three things: its natural nudist beach (one of Europe's most well-known), exceptional fresh-fish restaurants along the river, and world-class windsurfing and kitesurfing conditions. The sandy beach on the sea-facing side stretches for 3 km with shallow, warm water. Access is via a bridge from the mainland. Several rustic fish restaurants (čarde) serve river-fresh fish grilled over open flames.", "beach_type": "sandy", "featured": True, "parking_available": True, "pet_friendly": True, "popularity_score": 85, "tags": ["island", "naturist", "windsurfing", "river-delta"], "amenities": ["restaurants", "naturist-beach", "windsurfing-schools", "kitesurfing", "parking"], "best_for": ["windsurfing", "nature", "fresh-fish"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/beaches", "source_type": "curated"},
    {"name": "Ulcinj Old Town", "municipality_slug": "ulcinj", "category_slug": "tvrdjave-stari-gradovi", "lat": 41.9289, "lng": 19.2064, "short_description": "Ancient fortified town on a rocky promontory above the sea. Rich history including Illyrian, Roman, Venetian, and Ottoman periods.", "long_description": "Ulcinj's Old Town is an ancient fortified settlement perched on a rocky promontory above the Adriatic, with a history spanning Illyrian, Roman, Byzantine, Venetian, and Ottoman periods. The fortress walls, some dating to the 5th century, enclose a labyrinth of narrow streets with a distinctive North African feel. Notable sights include the Town Museum (in a former slave market - Ulcinj was once the northernmost slave trading post in the Mediterranean), the Balsic Tower, and several mosques and churches. The sunset views from the fortress walls are among the best in Montenegro.", "featured": True, "cultural_site": True, "parking_available": True, "pet_friendly": True, "popularity_score": 85, "tags": ["old-town", "fortress", "history", "multicultural"], "amenities": ["museum", "restaurants", "panoramic-views", "fortress-walls"], "best_for": ["history", "photography", "sunset"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/attractions", "source_type": "curated"},
    {"name": "Mala Plaža (Small Beach)", "municipality_slug": "ulcinj", "category_slug": "plaze", "lat": 41.9281, "lng": 19.2072, "short_description": "City beach right below the old town walls. Sandy, compact, and with a lively atmosphere during summer.", "long_description": "Mala Plaža (Small Beach) is the compact sandy city beach directly below Ulcinj's old town walls, creating one of the most scenic beach settings in Montenegro. The dark sand is rich in minerals and is said to have healing properties. During summer, the beach has a lively atmosphere with beach bars, sun lounger rental, and waterfront restaurants. The beach is within walking distance of all Ulcinj center accommodations. The medieval fortress walls rising above the beach make for dramatic photographs.", "beach_type": "sandy", "family_friendly": True, "parking_available": True, "pet_friendly": False, "popularity_score": 70, "tags": ["city-beach", "sandy", "old-town"], "amenities": ["sunbed-rental", "beach-bars", "restaurants", "showers"], "best_for": ["swimming", "photography", "convenience"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/beaches", "source_type": "curated"},
    {"name": "Ladies' Beach (Ženska Plaža)", "municipality_slug": "ulcinj", "category_slug": "plaze", "lat": 41.9272, "lng": 19.2047, "short_description": "Historically a women-only beach with supposedly healing mineral water. Now open to all, with a unique atmosphere.", "long_description": "Ženska Plaža (Ladies' Beach) has a unique history as a women-only bathing spot, where mineral-rich water was traditionally believed to aid fertility and cure various ailments. Now open to all visitors, the small rocky beach retains its distinctive atmosphere and the mineral water still flows. The beach is located a short walk from Mala Plaža, carved into the rocky coastline below the old town. A small entrance fee is charged. The warm mineral spring water mixing with the sea creates a unique swimming experience.", "beach_type": "rocky", "hidden_gem": True, "parking_available": False, "pet_friendly": False, "popularity_score": 55, "tags": ["unique", "historical", "mineral-water"], "amenities": ["mineral-water", "entrance-fee"], "best_for": ["wellness", "unique-experience", "swimming"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/beaches", "source_type": "curated"},
    {"name": "Šas Lake (Šasko Jezero)", "municipality_slug": "ulcinj", "category_slug": "priroda-vidikovci", "lat": 41.9583, "lng": 19.3167, "short_description": "Freshwater lake near Ulcinj, important bird sanctuary and wetland. Great for birdwatching, especially for pelicans.", "long_description": "Šasko Jezero (Šas Lake) is a freshwater lake near Ulcinj, serving as an important bird sanctuary and wetland habitat. The lake is home to numerous waterfowl species and is particularly notable for visiting Dalmatian Pelicans, one of the world's rarest pelican species. The surrounding marshland and reed beds create excellent birdwatching conditions, especially in spring and autumn. The lake is less visited than the Salina, offering a more wild and authentic nature experience. Access is via local roads from the Ulcinj-Shkodër highway.", "hidden_gem": True, "parking_available": True, "pet_friendly": True, "popularity_score": 50, "tags": ["lake", "birdwatching", "nature", "wetland"], "amenities": ["birdwatching"], "best_for": ["birdwatching", "nature", "tranquility"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/nature", "source_type": "curated"},
    {"name": "Valdanos Olive Grove", "municipality_slug": "ulcinj", "category_slug": "priroda-vidikovci", "lat": 41.9361, "lng": 19.1889, "short_description": "Ancient bay with over 80,000 olive trees, one of the largest olive groves on the Adriatic. Beautiful sheltered cove.", "long_description": "The Valdanos bay contains over 80,000 olive trees in one of the largest and oldest olive groves on the Adriatic coast. Some trees are centuries old, and the grove has been recognized as a natural monument. The sheltered bay features a small pebble beach with clear water surrounded by the olive-covered hillsides. The area is currently somewhat undeveloped, which preserves its wild beauty. The combination of ancient olive groves, clear swimming water, and untouched nature makes it one of the most unique spots on the Montenegrin coast.", "hidden_gem": True, "parking_available": True, "pet_friendly": True, "popularity_score": 55, "tags": ["olive-grove", "nature", "bay", "ancient"], "amenities": ["beach", "nature-walks"], "best_for": ["nature", "photography", "tranquility"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/nature", "source_type": "curated"},
    {"name": "Ulcinj Salina", "municipality_slug": "ulcinj", "category_slug": "priroda-vidikovci", "lat": 41.9100, "lng": 19.2400, "short_description": "Former salt production facility, now a key site for birdwatching with over 250 bird species including flamingos and pelicans.", "long_description": "The Ulcinj Salina is a former industrial salt production facility that has become one of the most important birdwatching sites in the Mediterranean. Over 250 bird species have been recorded here, including Greater Flamingos, Dalmatian Pelicans, and numerous wading birds. The flat, open landscape provides excellent viewing conditions, and the birds are often visible at relatively close range. The site has been the subject of international conservation efforts. Guided birdwatching tours are available, or visitors can explore independently along the access paths.", "featured": True, "parking_available": True, "pet_friendly": False, "popularity_score": 70, "tags": ["birdwatching", "flamingos", "nature-reserve", "salina"], "amenities": ["guided-tours", "observation-paths", "information-boards"], "best_for": ["birdwatching", "nature", "photography"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/nature", "source_type": "curated"},

    # ==================== NEW PLACES ====================

    # ========== HERCEG NOVI - New Places ==========
    {"name": "Dobreč Beach", "municipality_slug": "herceg-novi", "category_slug": "plaze", "lat": 42.3870, "lng": 18.5560, "short_description": "Blue Flag sandy beach on the Luštica peninsula, accessible only by boat. Pristine water and untouched Mediterranean beauty.", "long_description": "Dobreč is one of the most pristine beaches on the entire Montenegrin coast, earning a Blue Flag designation for its exceptional water quality. Located at the tip of the Luštica Peninsula, it can only be reached by water taxi from Herceg Novi (approximately 10-15 EUR round trip), which keeps crowds manageable even in peak season. The 600-square-meter beach features fine pebbles surrounded by lush vegetation, with a small beach restaurant serving fresh seafood. The crystal-clear water makes it excellent for snorkeling.", "beach_type": "pebble", "featured": True, "hidden_gem": True, "family_friendly": True, "parking_available": False, "pet_friendly": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 75, "tags": ["blue-flag", "boat-access", "pristine", "lustica"], "amenities": ["restaurant", "snorkeling"], "best_for": ["snorkeling", "swimming", "photography", "tranquility"], "accessibility_notes": "Boat access only. Not wheelchair accessible.", "source_url": "https://www.montenegropulse.com/herceg-novi-beaches.html", "source_type": "curated"},
    {"name": "Njivice Beach", "municipality_slug": "herceg-novi", "category_slug": "plaze", "lat": 42.4600, "lng": 18.4950, "short_description": "Nearly 1km-long sheltered beach combining sand, pebble, and concrete areas. Less crowded than city beaches with a relaxed atmosphere.", "long_description": "Located about 7 km west of Herceg Novi center in the settlement of Njivice, this spacious beach stretches for nearly a kilometer in a sheltered bay. The beach offers a combination of rocky, sandy, and concrete surfaces, giving visitors different swimming options. Regular bus service connects from Herceg Novi's main bus station for just 1.50 EUR one-way. The sheltered bay provides calm swimming conditions, making it suitable for families with young children.", "beach_type": "mixed", "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": True, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 55, "tags": ["sheltered", "spacious", "bus-accessible"], "amenities": ["parking", "bus-access"], "best_for": ["swimming", "families", "relaxation"], "accessibility_notes": None, "source_url": "https://www.visit-montenegro.com/destinations/herceg-novi/info/beaches/", "source_type": "curated"},
    {"name": "Konoba Feral", "municipality_slug": "herceg-novi", "category_slug": "restorani-beach-barovi", "lat": 42.4525, "lng": 18.5370, "short_description": "Family-run stone konoba on the old town waterfront, serving some of the best fresh seafood in the Bay of Kotor.", "long_description": "Konoba Feral is a genuine, family-run stone tavern located on the Herceg Novi waterfront near Forte Mare fortress. Built facing the fishing port, the restaurant gets daily deliveries of fresh fish and seafood of undeniable quality. Signature dishes include octopus salad, grilled whole fish, seafood risottos, and traditional Montenegrin soups. The intimate stone interior creates an authentic atmosphere, while the terrace offers views over the bay. A local institution beloved by both residents and visitors seeking traditional coastal dining.", "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 85, "tags": ["konoba", "seafood", "traditional", "waterfront"], "amenities": ["outdoor-seating", "waterfront-terrace"], "best_for": ["seafood", "romantic-dinner", "authentic-cuisine"], "accessibility_notes": None, "source_url": "https://www.montenegropulse.com/Herceg-novi-restaurants.html", "source_type": "curated"},
    {"name": "Konoba Škver", "municipality_slug": "herceg-novi", "category_slug": "restorani-beach-barovi", "lat": 42.4515, "lng": 18.5360, "short_description": "Historic port-side restaurant where the owner fishes for tuna each morning. Famous for seafood risottos and fresh catch.", "long_description": "Nestled right at sea level in Herceg Novi's charming port, Konoba Škver is a dining institution where the owner is a keen tuna fisherman who often heads out in the morning to seek fresh catch for diners. The restaurant is famous for wonderful traditional seafood risottos - both shrimp-and-saffron and classic black risotto. Squid, octopus, and grilled fish are prepared with simple Mediterranean perfection. The portside location means you dine just meters from the fishing boats that supply the kitchen.", "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["konoba", "seafood", "port-side", "fresh-fish"], "amenities": ["outdoor-seating", "port-views"], "best_for": ["seafood", "local-experience", "lunch"], "accessibility_notes": None, "source_url": "https://www.montenegropulse.com/Herceg-novi-restaurants.html", "source_type": "curated"},
    {"name": "Tondo Club & Bar", "municipality_slug": "herceg-novi", "category_slug": "nocni-zivot", "lat": 42.4530, "lng": 18.5340, "short_description": "Year-round music venue near the city park with marina views. Known for smooth house music, reggae, and drum & bass nights.", "long_description": "Tondo is Herceg Novi's premier year-round music venue, located near the city park with a stunning view of the marina. The club is known for playing quality music with a focus on smooth house, while also featuring reggae and drum & bass nights. The atmosphere is laid-back yet energetic, attracting a mix of locals and visitors. The outdoor terrace overlooking the bay makes it particularly atmospheric during summer evenings.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 70, "tags": ["club", "house-music", "marina-view", "year-round"], "amenities": [], "best_for": ["nightlife", "live-music", "cocktails"], "accessibility_notes": None, "source_url": "https://evendo.com/locations/montenegro/herceg-novi/best-bars", "source_type": "curated"},
    {"name": "La Bamba Beach Club", "municipality_slug": "herceg-novi", "category_slug": "nocni-zivot", "lat": 42.4500, "lng": 18.5320, "short_description": "Beachfront club for cocktails and live DJ sets. Dance barefoot on the sand with bay views and Mediterranean breezes.", "long_description": "La Bamba Beach Club is a popular seaside nightlife spot in Herceg Novi, perfect for those who want to combine beach vibes with evening entertainment. The club offers cocktails and live DJ sets against the backdrop of the Bay of Kotor. During summer evenings the energy builds from sunset cocktails to late-night dancing barefoot on the sand. The venue strikes a balance between relaxed beach bar and lively party spot.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 65, "tags": ["beach-club", "dj", "cocktails", "bay-views"], "amenities": [], "best_for": ["sunset-drinks", "dancing", "beach-party"], "accessibility_notes": None, "source_url": "https://emapark.com/discover-herceg-novis-nightlife/", "source_type": "curated"},
    {"name": "Adriatic Blue Diving Center", "municipality_slug": "herceg-novi", "category_slug": "aktivni-odmor", "lat": 42.4520, "lng": 18.5372, "short_description": "SSI-certified dive center operating since 2003. Explore the Tihany shipwreck, Mamula Island underwater sites, and the Blue Cave.", "long_description": "Adriatic Blue is the only SSI-certified dive center in Montenegro and has operated since 2003 from Herceg Novi's City Port Skver. They offer daily fun dives, wreck diving (including the famous Tihany shipwreck near Mamula Island), cave diving, and night dives. Introductory dives are available for beginners, and full certification courses for adults and children. The Mamula Island dive sites plunge to 30 meters and feature excellent marine diversity alongside fascinating Austro-Hungarian military history.", "active_holiday": True, "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "cultural_site": False, "popularity_score": 80, "tags": ["diving", "PADI", "SSI", "wreck-diving", "adventure"], "amenities": ["equipment-rental", "certified-instructors", "courses"], "best_for": ["diving", "snorkeling", "adventure", "certification"], "accessibility_notes": None, "source_url": "https://divingmontenegro.com/", "source_type": "curated"},
    {"name": "Pet Danica Promenade (Šetalište Pet Danica)", "municipality_slug": "herceg-novi", "category_slug": "porodicna-mjesta", "lat": 42.4560, "lng": 18.5200, "short_description": "6km seaside promenade stretching from Igalo through Herceg Novi to Meljine. Perfect for families with stalls, cafes, and shoreline views.", "long_description": "The Pet Danica Promenade is a beloved 6-kilometer coastal path stretching from Igalo through Herceg Novi center to the neighborhood of Meljine. The flat, paved walkway passes numerous cafes, restaurants, souvenir stalls, and swimming spots along the way. At the Igalo end near Tito's Villa, shallow sandy water and an abundance of crabs and fish make it a favorite spot for children of all ages. The promenade is stroller-friendly and offers constant views of the bay, making it one of the best family outings in the region.", "family_friendly": True, "featured": True, "parking_available": False, "pet_friendly": True, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 75, "tags": ["promenade", "seaside", "walking", "family"], "amenities": ["cafes", "restaurants", "stroller-friendly", "flat-path"], "best_for": ["families", "walking", "sunset-stroll", "kids"], "accessibility_notes": "Flat paved path, fully wheelchair and stroller accessible along the entire 6km route.", "source_url": "https://www.montenegropulse.com/herceg-novi-montenegro.html", "source_type": "curated"},

    # ========== KOTOR - New Places ==========
    {"name": "Dobrota Beach", "municipality_slug": "kotor", "category_slug": "plaze", "lat": 42.4350, "lng": 18.7750, "short_description": "7km waterfront stretch north of the old town with concrete and pebble sections. Peaceful setting with stunning bay views.", "long_description": "Dobrota's seafront extends 7 kilometers north along the coastal road from Kotor's Old Town, offering a mix of concrete swimming platforms and natural pebble sections. The village is peaceful and surrounded by untouched nature, with crystal-clear waters and beautiful views across the Bay of Kotor. Several waterfront cafes and restaurants dot the shoreline, and the gentle walk from the Old Town takes about 20 minutes. The sheltered bay provides calm swimming conditions throughout the season from mid-May to October.", "beach_type": "mixed", "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 55, "tags": ["waterfront", "village", "calm-water", "walking-distance"], "amenities": ["cafes", "restaurants", "parking"], "best_for": ["swimming", "walking", "relaxation"], "accessibility_notes": None, "source_url": "https://www.kotordirectory.com/listing-category/attractions/beaches-waterfronts/", "source_type": "curated"},
    {"name": "Stoliv Beach", "municipality_slug": "kotor", "category_slug": "plaze", "lat": 42.4650, "lng": 18.7200, "short_description": "Quiet concrete beach in a charming 14th-century village whose name means 'one hundred olives'. Peaceful and uncrowded.", "long_description": "The beautiful leafy village of Stoliv dates back to the 14th century, with its name meaning 'one hundred olives' reflecting the ancient olive groves that surround it. The small concrete beach has no commercial infrastructure but many nearby cafes and restaurants serve visitors. Located 10-15 km from Kotor, it is reachable by car or bicycle along the scenic bay road. A parking lot and pier provide easy access. Stoliv is one of the quietest and least-visited swimming spots in the Bay of Kotor, making it ideal for those seeking tranquility.", "beach_type": "rocky", "featured": False, "hidden_gem": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 40, "tags": ["village", "quiet", "historic", "olive-trees"], "amenities": ["parking", "pier", "cafes-nearby"], "best_for": ["tranquility", "swimming", "cycling-stop"], "accessibility_notes": None, "source_url": "http://www.montenegrofortravellers.com/en/review/beaches-kotor-and-risan-bay", "source_type": "curated"},
    {"name": "Konoba Scala Santa", "municipality_slug": "kotor", "category_slug": "restorani-beach-barovi", "lat": 42.4248, "lng": 18.7710, "short_description": "Charming old-town seafood restaurant with fisherman-cabin decor. Known for buttery, melt-in-your-mouth sea bass.", "long_description": "Konoba Scala Santa is a beloved seafood restaurant located in Kotor's Old Town, decorated with a fisherman's aesthetic that makes you feel like you're dining in the cabin of an old ship. The menu focuses on fresh Adriatic seafood, with the buttery sea bass fillet being a standout signature dish. The intimate stone interior creates a warm and authentic atmosphere. Located on one of the old town's quieter streets, it offers a respite from the cruise-ship crowds while delivering exceptional quality Montenegrin coastal cuisine.", "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["konoba", "seafood", "old-town", "cozy"], "amenities": ["indoor-seating", "air-conditioning"], "best_for": ["seafood", "romantic-dinner", "authentic-cuisine"], "accessibility_notes": None, "source_url": "https://twopacksandapup.com/10-kotor-restaurants-that-arent-tourist-traps/", "source_type": "curated"},
    {"name": "Ćatovića Mlini", "municipality_slug": "kotor", "category_slug": "restorani-beach-barovi", "lat": 42.4862, "lng": 18.6500, "short_description": "Legendary restaurant in a centuries-old stone mill in Morinj village. Dine among ancient stone arches beside a mountain stream.", "long_description": "Ćatovića Mlini is consistently rated as one of Montenegro's top restaurants, set in a centuries-old stone mill in the tiny village of Morinj. The Catovic family has used these mills for over 200 years, and in the last 25 years transformed the site into an extraordinary dining destination. You dine among ancient stone arches with a mountain stream flowing through the restaurant. Seafood dominates the menu, with fresh catches prepared in traditional Boka Bay style. Open 12:00-21:30. Reservations strongly recommended in summer.", "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 95, "tags": ["fine-dining", "historic", "stone-mill", "stream-side"], "amenities": ["parking", "outdoor-seating", "historic-setting"], "best_for": ["special-occasion", "seafood", "romantic-dinner", "photography"], "accessibility_notes": None, "source_url": "https://www.catovica-mlini.com/en/", "source_type": "curated"},
    {"name": "Maximus Nightclub", "municipality_slug": "kotor", "category_slug": "nocni-zivot", "lat": 42.4240, "lng": 18.7700, "short_description": "One of the largest nightclubs in Montenegro with 4,000 person capacity. International DJs, techno, house, and pop music year-round.", "long_description": "Maximus is one of the most famous nightclubs not only in Kotor but in all of Montenegro. Located just outside the Old Town walls, this massive venue has a capacity of up to 4,000 people, attracting both locals and tourists with its high-energy atmosphere. The club regularly hosts local and international DJs covering techno, house, pop, and hip-hop genres. Operating year-round, it transforms from summer open-air parties to indoor winter events. The venue's proximity to the Old Town makes it the natural culmination of a Kotor night out.", "nightlife": True, "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 85, "tags": ["nightclub", "large-venue", "international-djs", "year-round"], "amenities": [], "best_for": ["nightlife", "dancing", "dj-events"], "accessibility_notes": None, "source_url": "https://www.visit-montenegro.com/destinations/kotor/info/night-clubs/", "source_type": "curated"},
    {"name": "Letrika Bar", "municipality_slug": "kotor", "category_slug": "nocni-zivot", "lat": 42.4245, "lng": 18.7715, "short_description": "Atmospheric side-alley bar in Kotor's Old Town. Quiet daytime drinks transform into vibrant DJ nights with dancing in the street.", "long_description": "Letrika occupies a side alley in Kotor's Old Town, offering a quiet spot for a drink during the day that transforms completely on summer nights. When darkness falls, the narrow alley gets jammed with young people dancing and sipping cocktails while DJs perform from the tiny venue, spilling their beats into the cobblestone street. The contrast between its daytime calm and nighttime energy makes it one of Kotor's most unique nightlife experiences. Cocktail prices are reasonable by Old Town standards.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 70, "tags": ["bar", "old-town", "dj", "alley-bar", "cocktails"], "amenities": [], "best_for": ["nightlife", "cocktails", "atmosphere"], "accessibility_notes": None, "source_url": "https://twopacksandapup.com/kotor-nightlife-the-best-bars-in-old-town/", "source_type": "curated"},
    {"name": "Blue Cave Kayak Adventure", "municipality_slug": "kotor", "category_slug": "aktivni-odmor", "lat": 42.3889, "lng": 18.5594, "short_description": "Guided kayak tours to the Blue Cave and surrounding sea caves. No experience needed; gear and safety briefing provided.", "long_description": "Several operators (Montenegro+, Adventure Montenegro) offer guided kayak tours to the Blue Cave and surrounding sea caves from departure points near Muo and the Luštica Peninsula. The tours use stable inflatable sit-on-top kayaks suitable for complete beginners, with guides providing detailed safety briefings before setting off. Half-day tours cover approximately 6 km of paddling with stops for snorkeling, departing at 10 AM and 3 PM. Prices start at around 20 EUR per person. Kayaks can access smaller caves that speedboats cannot reach.", "active_holiday": True, "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "cultural_site": False, "popularity_score": 85, "tags": ["kayaking", "blue-cave", "guided-tour", "snorkeling", "adventure"], "amenities": ["equipment-provided", "guides", "snorkel-gear"], "best_for": ["adventure", "kayaking", "snorkeling", "photography"], "accessibility_notes": None, "source_url": "https://www.montenegroplus.me/blue-cave-kayak", "source_type": "curated"},
    {"name": "Vrmac Peninsula Mountain Biking", "municipality_slug": "kotor", "category_slug": "aktivni-odmor", "lat": 42.4400, "lng": 18.7300, "short_description": "Mountain biking tours on the Vrmac ridge between Kotor and Tivat. Reach Fort Vrmac at 480m and Saint Ilija peak at 760m for panoramic views.", "long_description": "The Vrmac Peninsula offers premier mountain biking with tours starting from Trojica pass, climbing 4km on road to the Austro-Hungarian Fort Vrmac at 480 meters, then continuing off-road to Saint Ilija peak at 760 meters. Saint Ilija is unique in the Bay of Kotor as the only point from which you can see the entire bay. Guided tours last approximately 3 hours with 2 hours of cycling and include short walks into old forts. The strenuous ascend tour requires significant MTB experience, while moderate-difficulty options with more downhill segments are also available.", "active_holiday": True, "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "cultural_site": False, "popularity_score": 75, "tags": ["mountain-biking", "vrmac", "panorama", "fort", "adventure"], "amenities": ["bike-rental", "guides", "helmets"], "best_for": ["mountain-biking", "adventure", "panoramic-views", "fitness"], "accessibility_notes": None, "source_url": "https://www.montenegroplus.me/vrmac-mtb-tour", "source_type": "curated"},

    # ========== TIVAT - New Places ==========
    {"name": "Oblatno Beach", "municipality_slug": "tivat", "category_slug": "plaze", "lat": 42.3811, "lng": 18.6647, "short_description": "Scenic Luštica peninsula beach home to the famous Almara Beach Club. Pebble shores with turquoise water and full-service amenities.", "long_description": "Oblatno Beach is a beautiful pebble beach on the Luštica Peninsula, best known as the home of the Almara Beach Club. The beach offers sun loungers, umbrellas, and full restaurant and bar service, making it one of the most well-equipped beaches in the Tivat area. The turquoise water is excellent for swimming, and the beach transforms into a nightlife venue after sunset with DJ sets and themed parties. Accessible by car from Tivat (approximately 15 minutes) with parking available. The beach is also accessible from Luštica Bay resort.", "beach_type": "pebble", "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "nightlife": True, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["beach-club", "lustica", "amenities", "nightlife"], "amenities": ["sunbed-rental", "restaurant", "bar", "parking", "changing-rooms", "showers"], "best_for": ["sunbathing", "swimming", "sunset", "beach-party"], "accessibility_notes": None, "source_url": "https://www.beachatlas.com/oblatno", "source_type": "curated"},
    {"name": "ONE Restaurant & Bar", "municipality_slug": "tivat", "category_slug": "restorani-beach-barovi", "lat": 42.4352, "lng": 18.6918, "short_description": "Porto Montenegro's flagship restaurant since 2011. Contemporary Adriatic-Continental cuisine with an international wine list.", "long_description": "ONE was established in 2011 as the first restaurant in Porto Montenegro's superyacht marina and remains a magnet for yachties, expats, and stylish visitors from across the region. The menu features local, seasonal, and frequently refreshed contemporary Adriatic-Continental cuisine paired with an excellent international wine list. The waterfront terrace offers prime marina views, and the interior is sleek and modern. Rated 4.3/5 on TripAdvisor and ranked among the top restaurants in Tivat. Ideal for a refined lunch or dinner with marina ambiance.", "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 85, "tags": ["fine-dining", "porto-montenegro", "marina", "wine"], "amenities": ["outdoor-terrace", "marina-views", "air-conditioning", "wine-list"], "best_for": ["fine-dining", "marina-views", "wine", "special-occasion"], "accessibility_notes": None, "source_url": "https://www.myguidemontenegro.com/restaurants/one", "source_type": "curated"},
    {"name": "Prova Restaurant", "municipality_slug": "tivat", "category_slug": "restorani-beach-barovi", "lat": 42.4345, "lng": 18.6925, "short_description": "Ship-shaped building on Tivat's promenade with bay-view rooftop dining. Contemporary cuisine for breakfast, lunch, and dinner.", "long_description": "Prova is located on the main promenade in central Tivat, housed in a distinctive building shaped like a ship. The restaurant offers seating on the seafront terrace or the rooftop, both overlooking the bay. The menu features contemporary Mediterranean cuisine suitable for any meal of the day. The unique architectural design, combined with panoramic bay views from the rooftop, makes it one of Tivat's most distinctive dining experiences. Popular with both visitors and locals, it serves as an excellent starting point for an evening walk along the waterfront.", "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 70, "tags": ["contemporary", "rooftop", "bay-views", "ship-building"], "amenities": ["rooftop-terrace", "waterfront", "air-conditioning"], "best_for": ["bay-views", "rooftop-dining", "casual-dining"], "accessibility_notes": None, "source_url": "https://gokii.digital/best-restaurants-tivat/", "source_type": "curated"},
    {"name": "Almara Beach Club", "municipality_slug": "tivat", "category_slug": "nocni-zivot", "lat": 42.3815, "lng": 18.6650, "short_description": "Premier beach club on the Luštica Peninsula. Upscale daytime lounging transforms into DJ nights and themed parties after sunset.", "long_description": "Almara Beach Club on the Luštica Peninsula (Oblatno beach) is one of Montenegro's most prestigious beach clubs. During the day it offers premium sun lounger service, excellent Mediterranean cuisine, and crystal-clear swimming waters. After sunset, Almara transforms into a nightlife hotspot with live DJs, themed parties, and expertly crafted cocktails. The club attracts a mix of locals, marina guests from nearby Luštica Bay, and visitors from across the bay. Events range from chill sunset sessions to high-energy weekend parties.", "nightlife": True, "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["beach-club", "dj", "lustica", "upscale", "cocktails"], "amenities": ["sunbed-rental", "restaurant", "bar", "parking", "dj-events"], "best_for": ["beach-party", "sunset-drinks", "nightlife", "cocktails"], "accessibility_notes": None, "source_url": "https://lusticabay.com/lustica-bay-beach/", "source_type": "curated"},
    {"name": "Buddha-Bar Tivat", "municipality_slug": "tivat", "category_slug": "nocni-zivot", "lat": 42.4355, "lng": 18.6910, "short_description": "Luxury lounge bar in Porto Montenegro with international DJs, bay views, and a blend of upscale nightlife and beach-club vibes.", "long_description": "Part of the global Buddha-Bar franchise, this Porto Montenegro outpost is the perfect blend of luxury and laid-back beach club vibes, set right by the stunning Bay of Kotor. International DJs take over as the sun goes down, turning the place into a buzzing nightclub. The venue features an extensive cocktail menu, Asian-fusion cuisine, and distinctive Buddha-Bar decor. The waterfront setting within the marina village provides beautiful backdrop of superyachts and bay views. Popular for both pre-dinner cocktails and late-night entertainment.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 75, "tags": ["lounge", "porto-montenegro", "luxury", "international-dj"], "amenities": [], "best_for": ["nightlife", "cocktails", "luxury-experience"], "accessibility_notes": None, "source_url": "https://www.portomontenegro.com/blog/montenegro-nightlife-guide-all-you-need-to-know/", "source_type": "curated"},
    {"name": "Scaramanga Bar", "municipality_slug": "tivat", "category_slug": "nocni-zivot", "lat": 42.4350, "lng": 18.6915, "short_description": "Elegant marina-side cocktail bar in Porto Montenegro. Signature cocktails with stunning yacht and bay views.", "long_description": "Scaramanga Bar is an elegant cocktail venue within Porto Montenegro's marina village, combining signature cocktails with stunning views of yachts and the Bay of Kotor. The bar attracts a stylish crowd and is perfect for a romantic evening or a gathering with friends. The menu features creative cocktails alongside a curated wine and spirits selection. The outdoor terrace offers prime marina-watching, while the interior provides a more intimate setting. It sits at the heart of Porto Montenegro's evening scene.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 70, "tags": ["cocktail-bar", "porto-montenegro", "marina", "elegant"], "amenities": [], "best_for": ["cocktails", "romantic-evening", "marina-views"], "accessibility_notes": None, "source_url": "https://emapark.com/exploring-tivat-nightlife/", "source_type": "curated"},
    {"name": "Luštica Bay Water Sports Center", "municipality_slug": "tivat", "category_slug": "aktivni-odmor", "lat": 42.3900, "lng": 18.6700, "short_description": "Water sports center on the Luštica Peninsula offering kayaking, SUP, and snorkeling with guided coastal excursions.", "long_description": "The water sports center at Luštica Bay resort offers kayaking, stand-up paddleboarding (SUP), and snorkeling experiences along the stunning Luštica Peninsula coastline. Guided excursions explore hidden coves, sea caves, and crystal-clear swimming spots inaccessible by road. Equipment is provided for all activities, and no prior experience is necessary for most programs. The calm, sheltered waters of the bay make conditions ideal for beginners. SUP yoga sessions and sunset paddle tours are available during peak season.", "active_holiday": True, "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "cultural_site": False, "popularity_score": 65, "tags": ["kayaking", "SUP", "snorkeling", "water-sports", "guided"], "amenities": ["equipment-provided", "guides", "beginner-friendly"], "best_for": ["kayaking", "SUP", "snorkeling", "families"], "accessibility_notes": None, "source_url": "https://lusticabay.com/", "source_type": "curated"},
    {"name": "Island of Flowers Nature Trail", "municipality_slug": "tivat", "category_slug": "porodicna-mjesta", "lat": 42.4115, "lng": 18.6826, "short_description": "Easy family walk through the botanical peninsula with medieval monastery ruins, exotic plants, and bay views. Connected by a short bridge.", "long_description": "The Island of Flowers (Miholjska Prevlaka) is a small peninsula connected to the mainland by a short bridge, making it an ideal family excursion from Tivat. The easy walking trail winds through diverse Mediterranean and exotic plant species, past medieval monastery ruins, and offers continuous bay views. The flat, well-maintained paths are suitable for strollers and young walkers. There are shaded areas for picnics and benches along the route. The combination of nature, history, and gentle exercise makes it one of the best family-friendly activities in Tivat.", "family_friendly": True, "featured": False, "parking_available": True, "pet_friendly": True, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 75, "tags": ["family", "nature-trail", "botanical", "monastery", "easy-walk"], "amenities": ["benches", "shade", "flat-paths", "stroller-friendly"], "best_for": ["families", "nature-walk", "kids", "photography"], "accessibility_notes": "Mostly flat paths accessible by stroller. Some uneven sections near monastery ruins.", "source_url": "https://tivat.travel/en/nature", "source_type": "curated"},

    # ========== BUDVA - New Places ==========
    {"name": "Drobni Pijesak Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2341, "lng": 18.9042, "short_description": "Hidden sandy beach between Sveti Stefan and Petrovac with fine golden sand, a natural freshwater spring, and unspoiled tropical feel.", "long_description": "Drobni Pijesak (meaning 'Crushed Sand') is a 250-meter hidden beach located between Sveti Stefan and Petrovac on the Budva Riviera. The beach features fine yellow-white sand and smooth pebbles giving it a tropical feel, and is considered one of Montenegro's best 'wild beaches' - unspoiled yet welcoming. A natural freshwater spring nearby is an uncommon and refreshing feature for a seaside location. There is a small beach bar and restaurant, plus a mooring platform for diving into the Adriatic. Access is via a steep path from the main road, about 7.8 km from Budva center.", "beach_type": "sandy", "featured": False, "hidden_gem": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 70, "tags": ["hidden-beach", "sandy", "wild", "freshwater-spring", "tropical"], "amenities": ["beach-bar", "restaurant", "parking"], "best_for": ["swimming", "tranquility", "snorkeling", "photography"], "accessibility_notes": "Steep path from road to beach. Not wheelchair accessible.", "source_url": "https://sandee.com/montenegro/budva/drobnici/drobni-pijesak-beach", "source_type": "curated"},
    {"name": "Pržno Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2686, "lng": 18.8924, "short_description": "Charming 350m beach in a fishing village backed by olive groves. West-facing for spectacular sunsets. Mix of sand and rocky sections.", "long_description": "Pržno is a combination of partly sandy and partly rocky beach stretching 350 meters in a traditional fishing village between Budva and Sveti Stefan. The beach is backed by olive groves of extreme ecological value, making the entire locality a protected natural reservation. Facing west, the sunset here is particularly spectacular. The village maintains its authentic fishing character with several excellent seafood restaurants right on the waterfront. Less developed than Budva's main beaches, Pržno offers a more authentic Montenegrin coastal experience.", "beach_type": "mixed", "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 65, "tags": ["fishing-village", "sunset", "olive-groves", "authentic"], "amenities": ["restaurants", "parking"], "best_for": ["sunset", "photography", "authentic-experience", "dining"], "accessibility_notes": None, "source_url": "https://www.montenegropulse.com/budva-beaches.html", "source_type": "curated"},
    {"name": "Konoba Stari Grad", "municipality_slug": "budva", "category_slug": "restorani-beach-barovi", "lat": 42.2890, "lng": 18.8380, "short_description": "Traditional konoba tucked behind stone walls in Budva's Old Town. Family-run, with own-brewed beer, live music, and summer beach seating.", "long_description": "Tucked away behind a stone facade in Budva's old town, Konoba Stari Grad epitomizes coastal Montenegrin dining. The family-run restaurant serves traditional Montenegrin cuisine including whole fish with dalmatinsko varivo (Dalmatian-style silver beet and potato with garlic), and also brews its own beer. An intimate stone interior creates an authentic atmosphere, while in summer you can take a table on the beach. A live musician serenades diners in the evening, completing the traditional Montenegrin dining experience.", "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["konoba", "old-town", "live-music", "craft-beer", "traditional"], "amenities": ["outdoor-seating", "beach-tables", "live-music"], "best_for": ["traditional-food", "live-music", "romantic-dinner", "local-experience"], "accessibility_notes": None, "source_url": "https://theculturetrip.com/europe/montenegro/articles/the-10-best-restaurants-in-budva-montenegro", "source_type": "curated"},
    {"name": "Jadran Kod Krsta", "municipality_slug": "budva", "category_slug": "restorani-beach-barovi", "lat": 42.2885, "lng": 18.8390, "short_description": "Seaside institution for over 40 years, with tables on the sand. Famous for the fish plate for two, fresh catch, and local wine.", "long_description": "Jadran Kod Krsta is one of the oldest and most established restaurants in Budva, serving traditional coastal cuisine for over 40 years from its prime seaside promenade location. Whole fish, octopus, calamari, and shellfish are all excellent here, prepared simply with a squeeze of lemon, garlic, parsley, and paired with local red wine. The idyllic setting features tables directly on the sand, and the fish plate for two is the signature recommendation. Live rock music occasionally accompanies the dining experience, creating a uniquely Budva atmosphere.", "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["seafood", "seaside", "institution", "40-years"], "amenities": ["beach-seating", "seaside-terrace"], "best_for": ["seafood", "romantic-dinner", "sunset-dining"], "accessibility_notes": None, "source_url": "https://www.montenegropulse.com/best-budva-restaurants.html", "source_type": "curated"},
    {"name": "Dukley Beach & Bar", "municipality_slug": "budva", "category_slug": "restorani-beach-barovi", "lat": 42.2830, "lng": 18.8510, "short_description": "Upscale beach dining between Budva and Bečići with fine sand, champagne bar, and innovative 'New Mediterranean' cuisine.", "long_description": "Dukley Beach & Bar is an urban oasis offering three beach sections: the upscale VIP Beach, the sandy Moet et Chandon Beach, and the Lagoon Beach. The restaurant features a cantilevered terrace over the beach and serves innovative 'New Mediterranean' cuisine with a focus on fresh, simple dishes perfect for lunch and sharing. The champagne and cocktail bar adds a touch of luxury to the beach experience. Part of the Dukley Hotels collection, it represents the premium end of Budva's beach dining scene with comfortable sunbeds and attentive service.", "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 85, "tags": ["upscale", "beach-bar", "new-mediterranean", "champagne", "luxury"], "amenities": ["sunbed-rental", "champagne-bar", "restaurant", "vip-section", "showers"], "best_for": ["upscale-dining", "beach-luxury", "cocktails", "sunbathing"], "accessibility_notes": None, "source_url": "https://www.dukleyhotels.com/en/dining/dukley-beach-bar", "source_type": "curated"},
    {"name": "Top Hill", "municipality_slug": "budva", "category_slug": "nocni-zivot", "lat": 42.2938, "lng": 18.8223, "short_description": "The largest and most famous open-air nightclub in the Balkans, perched on Topliš hill at 160m elevation with Adriatic panoramic views.", "long_description": "Top Hill is the crown jewel of Montenegrin nightlife, an open-air mega-club perched on Topliš hill at 160 meters elevation overlooking Budva and the Adriatic. With a massive dance floor, state-of-the-art sound and lighting systems, and multiple bars, it regularly hosts world-famous international DJs. The club operates during summer season (June-September) with events typically starting around midnight and running until dawn. Located about 2 km from Budva center via Topliški put, shuttles and taxis are readily available. VIP tables and bottle service available.", "nightlife": True, "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 95, "tags": ["mega-club", "open-air", "international-dj", "panoramic", "iconic"], "amenities": ["parking", "vip-area", "multiple-bars", "shuttle-service"], "best_for": ["nightlife", "dancing", "dj-events", "panoramic-views"], "accessibility_notes": None, "source_url": "https://www.tophill.me/", "source_type": "curated"},
    {"name": "Club Sparta", "municipality_slug": "budva", "category_slug": "nocni-zivot", "lat": 42.2895, "lng": 18.8385, "short_description": "Stylish and intimate nightclub near the Old Town with ancient-themed decor. Curated electronic, R&B, and house music lineup.", "long_description": "Club Sparta brings a unique atmosphere to Budva's nightlife with its ancient-themed decor and carefully curated music lineup ranging from electronic to R&B and house. Located near the Old Town, the stylish and intimate venue attracts a trendy, upscale crowd looking for a more exclusive night out compared to the mega-clubs. The club features VIP areas and a quality sound system in a more personal setting. Popular as either a warm-up venue before Top Hill or as the main destination for those preferring a more refined clubbing experience.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 70, "tags": ["nightclub", "upscale", "themed-decor", "intimate"], "amenities": [], "best_for": ["nightlife", "upscale-clubbing", "cocktails"], "accessibility_notes": None, "source_url": "https://twopacksandapup.com/budva-nightlife-breakdown-all-the-top-spots-to-party/", "source_type": "curated"},
    {"name": "Budva Paragliding from Brajići", "municipality_slug": "budva", "category_slug": "aktivni-odmor", "lat": 42.2700, "lng": 18.8200, "short_description": "Tandem paragliding from 765m above sea level. Soar over Sveti Stefan, Bečići, and the island of Sveti Nikola with expert pilots.", "long_description": "Multiple certified operators (Go2fly, Budva Paragliding since 1993, Paragliding Montenegro) offer tandem paragliding flights launching from Brajići at 765 meters above sea level, with landings near Bečići beach. Flights last 15-30+ minutes depending on conditions, offering panoramic views over Sveti Stefan, Miločer, Bečići, Budva, and the island of Sveti Nikola. No previous experience is required - each passenger flies with their own certified pilot. The activity is suitable for individuals, couples, families, or groups. GoPro video footage is typically available as an add-on.", "active_holiday": True, "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "cultural_site": False, "popularity_score": 85, "tags": ["paragliding", "tandem", "adventure", "panoramic", "adrenaline"], "amenities": ["certified-pilots", "transport-to-launch", "photo-video"], "best_for": ["adventure", "panoramic-views", "adrenaline", "photography"], "accessibility_notes": None, "source_url": "https://budva-paragliding.me/", "source_type": "curated"},
    {"name": "Sveti Nikola Island (Hawaii)", "municipality_slug": "budva", "category_slug": "porodicna-mjesta", "lat": 42.2850, "lng": 18.8450, "short_description": "Car-free island opposite Budva accessible by water taxi. Three beaches, a small church, deer roaming freely, and a relaxed family atmosphere.", "long_description": "Sveti Nikola Island, affectionately nicknamed 'Hawaii' by locals, is the largest island on the Montenegrin coast, sitting just opposite Budva. Water taxis run regularly from Budva, Bečići, and Slovenska Plaža during summer (approximately 3-5 EUR). The car-free island features three beaches (pebble and rocky), a small medieval church, and a population of deer that roam freely. The island offers a peaceful escape from Budva's summer bustle, with beach bars and restaurants operating during the season. The shallow waters on the Budva-facing side are ideal for children.", "family_friendly": True, "featured": True, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["island", "car-free", "water-taxi", "deer", "family"], "amenities": ["beach-bars", "restaurants", "water-taxi"], "best_for": ["families", "day-trip", "swimming", "nature"], "accessibility_notes": None, "source_url": "https://budva.travel/en/attractions", "source_type": "curated"},
    {"name": "Petrovac Beach", "municipality_slug": "budva", "category_slug": "plaze", "lat": 42.2083, "lng": 18.9306, "short_description": "Charming 600m red-pebble beach in the resort town of Petrovac. Venetian fortress, offshore islands, and a lively promenade with pine trees.", "long_description": "Petrovac Beach is a 600-meter stretch of distinctive red pebbles in the charming resort town of Petrovac, about 17 km south of Budva. The beach is flanked by a Venetian fortress (Castello) at one end and offers views of two small offshore islands - Sveta Nedjelja and Katič with its tiny chapel. A lively promenade lined with pine trees, restaurants, and shops runs behind the beach. The calm, crystal-clear turquoise waters are ideal for swimming and snorkeling, and the gentle entry makes it family-friendly. Pine trees provide natural shade along the edges of the beach.", "beach_type": "pebble", "featured": True, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["resort", "red-pebble", "fortress", "islands", "promenade"], "amenities": ["restaurants", "shops", "sunbed-rental", "water-sports", "parking", "showers"], "best_for": ["families", "swimming", "promenade-walks", "snorkeling"], "accessibility_notes": None, "source_url": "https://www.montenegropulse.com/budva-beaches.html", "source_type": "curated"},

