    {"name": "Maljevik Beach", "municipality_slug": "bar", "category_slug": "plaze", "lat": 42.1380, "lng": 19.0350, "short_description": "300m pebble beach near Sutomore with health-beneficial mud and clay. Partly naturist, with a beach restaurant and basic amenities.", "long_description": "Maljevik is a distinctive 300-meter beach near Sutomore, about 10 km from Bar, known for its health-beneficial mud and clay deposits. The main surface consists of small pebbles with rocks and some trees providing natural shade. The far end of the beach is reserved for naturists. Access requires descending concrete steps about 25 meters to the beach, with a dirt parking area just meters from the top. A beach restaurant serves hamburgers, pizza, and ćevapi, with changing rooms, showers, toilets, and a beach bar completing the basic amenities.", "beach_type": "pebble", "featured": False, "hidden_gem": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 50, "tags": ["naturist", "healing-mud", "secluded", "pebble"], "amenities": ["restaurant", "changing-rooms", "showers", "toilets", "beach-bar", "parking"], "best_for": ["tranquility", "naturism", "wellness", "swimming"], "accessibility_notes": "25-meter descent via concrete steps required. Not wheelchair accessible.", "source_url": "https://www.beachrex.com/en/montenegro/bar/sutomore-beaches/beach-maljevik", "source_type": "curated"},
    {"name": "Utjeha Beach", "municipality_slug": "bar", "category_slug": "plaze", "lat": 42.1150, "lng": 19.0650, "short_description": "Scenic family beach in Oliva bay surrounded by olive trees. Mix of sand and pebbles with crystal-clear turquoise waters.", "long_description": "Utjeha is a scenic stretch of coastline in Oliva bay, known for its rugged beauty and family-friendly conditions. Surrounded by olive trees and Mediterranean vegetation, the beach features a mix of sand and pebbles with crystal-clear turquoise waters. The sheltered bay provides calm swimming conditions ideal for families with children. Several small restaurants and apartments dot the coastline. Located between Bar and Ulcinj, Utjeha offers a quieter alternative to the busier resort beaches while still providing basic amenities and services.", "beach_type": "mixed", "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": True, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 55, "tags": ["olive-trees", "family", "turquoise", "sheltered"], "amenities": ["restaurants", "parking", "apartments-nearby"], "best_for": ["families", "swimming", "relaxation", "quiet-holiday"], "accessibility_notes": None, "source_url": "https://www.visit-montenegro.com/destinations/bar/info/beaches/", "source_type": "curated"},
    {"name": "Dobra Voda Beach", "municipality_slug": "bar", "category_slug": "plaze", "lat": 42.1050, "lng": 19.0550, "short_description": "600m sandy beach in a charming coastal village between Bar and Ulcinj. Calm, private atmosphere with water sports and beach bars.", "long_description": "Dobra Voda is a charming coastal village approximately 10 km south of Bar, nestled between lush hills and the crystal-clear Adriatic Sea. The main beach stretches approximately 600 meters of sandy shore with water sports facilities available in season. Compared to Sutomore's busy resort atmosphere, Dobra Voda offers a more calm and private beach experience. Modest nightlife centers around beach bars and restaurants that occasionally feature live music in summer. The village is a favorite with visitors seeking an authentic, less commercialized Montenegrin coastal experience.", "beach_type": "sandy", "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 50, "tags": ["village", "sandy", "calm", "authentic"], "amenities": ["water-sports", "beach-bars", "restaurants", "parking"], "best_for": ["relaxation", "families", "authentic-experience"], "accessibility_notes": None, "source_url": "https://www.dobra-voda.com/", "source_type": "curated"},
    {"name": "Parapet Pizza & Grill", "municipality_slug": "bar", "category_slug": "restorani-beach-barovi", "lat": 42.0940, "lng": 19.1000, "short_description": "Year-round coastal promenade restaurant in Bar, a favorite among locals. Pizza, grilled meats, and seafood with sea views.", "long_description": "Parapet Pizza & Grill is located along Bar's coastal promenade and remains open year-round, making it a rare reliable dining option outside peak season. The restaurant is a favorite among both locals and visitors, serving excellent pizza, grilled meats, and fresh seafood. The promenade setting provides sea views and a pleasant atmosphere for dining. Near King Nikola's Palace and the city marina, it serves as a convenient stop during a waterfront exploration of Bar. The menu offers good value with generous portions.", "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 65, "tags": ["year-round", "promenade", "pizza", "grill", "local-favorite"], "amenities": ["outdoor-seating", "sea-views"], "best_for": ["casual-dining", "pizza", "year-round-dining"], "accessibility_notes": None, "source_url": "https://www.tripadvisor.com/Restaurants-g608961-Bar_Bar_Municipality.html", "source_type": "curated"},
    {"name": "Sutomore Beach Bar Strip", "municipality_slug": "bar", "category_slug": "nocni-zivot", "lat": 42.1440, "lng": 19.0420, "short_description": "Vibrant beachfront nightlife strip in Sutomore with bars, live music, and summer concerts. Popular with young travelers.", "long_description": "Sutomore's beachfront comes alive at night during summer with a vibrant strip of bars, clubs, and live music venues lining the sandy beach. The resort town is known for its energetic nightlife, featuring everything from cocktail bars with coastal views to open-air venues hosting live concerts and DJ sets. The nightlife scene is particularly popular among young travelers and locals, with drinks priced affordably at 3-6 EUR. The atmosphere peaks in July and August when the beach bars extend their hours deep into the night.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 65, "tags": ["beach-bars", "live-music", "summer-nightlife", "affordable"], "amenities": [], "best_for": ["nightlife", "live-music", "beach-party", "budget-friendly"], "accessibility_notes": None, "source_url": "https://montenegro.org/sutomore-the-small-coastal-town-in-montenegro/", "source_type": "curated"},
    {"name": "Stari Bar Hiking Trail", "municipality_slug": "bar", "category_slug": "aktivni-odmor", "lat": 42.0910, "lng": 19.1310, "short_description": "Scenic hike through olive groves to the medieval fortress ruins of Stari Bar. Explore 240+ ancient buildings, an aqueduct, and hamam.", "long_description": "The trail to Stari Bar (Old Bar) takes hikers through centuries-old olive groves, including some trees over 2,000 years old, up to the impressive medieval fortress ruins perched on a hillside 4 km from the coast. The archaeological site contains over 240 buildings, a well-preserved aqueduct, churches from various periods, and Ottoman hamam (bathhouse) ruins dating to the 6th century. The moderate hike takes about 30-45 minutes from the lower parking area. The fortress offers panoramic views over modern Bar, the coast, and Lake Skadar in the distance. Early morning or late afternoon visits are recommended to avoid summer heat.", "active_holiday": True, "featured": False, "cultural_site": True, "family_friendly": False, "parking_available": True, "pet_friendly": True, "hidden_gem": False, "nightlife": False, "popularity_score": 80, "tags": ["hiking", "medieval-ruins", "olive-groves", "archaeology", "panorama"], "amenities": ["parking", "guided-tours-available", "museum-on-site"], "best_for": ["hiking", "history", "photography", "exploration"], "accessibility_notes": None, "source_url": "https://bar.travel/en/attractions", "source_type": "curated"},
    {"name": "Sutomore Family Beach Zone", "municipality_slug": "bar", "category_slug": "porodicna-mjesta", "lat": 42.1440, "lng": 19.0415, "short_description": "Sandy family beach zone in Sutomore with shallow warm water, pine tree shade, and nearby playgrounds. One of Montenegro's top family destinations.", "long_description": "Sutomore's family beach zone occupies the central portion of the resort's long sandy beach, offering ideal conditions for families with young children. The sandy bottom and gradually deepening water create a safe swimming environment, while pine forests behind the beach provide natural shade for picnics and rest. The beach has full facilities including sunbed rental, cafes, restaurants, and nearby playgrounds. Sutomore is connected by train from Bar and Podgorica, making it one of the most accessible beach resorts for families traveling without a car. Accommodations range from hotels to family apartments directly behind the beach.", "family_friendly": True, "featured": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 75, "tags": ["family", "sandy", "pine-trees", "train-accessible", "shallow-water"], "amenities": ["sunbed-rental", "cafes", "restaurants", "playgrounds", "shade", "train-station"], "best_for": ["families", "kids", "swimming", "budget-holiday"], "accessibility_notes": "Flat sandy beach accessible from the promenade. Train station within walking distance.", "source_url": "https://www.visit-montenegro.com/destinations/bar/info/beaches/", "source_type": "curated"},

    # ========== ULCINJ - New Places ==========
    {"name": "Valdanos Beach", "municipality_slug": "ulcinj", "category_slug": "plaze", "lat": 41.9370, "lng": 19.1900, "short_description": "Sheltered bay beach surrounded by 80,000 olive trees. Pebble shores with clear water in one of the largest olive groves on the Adriatic.", "long_description": "Valdanos is a beautiful sheltered cove surrounded by one of the largest olive groves on the Adriatic, containing over 80,000 olive trees. The pebble beach offers clear swimming water in a setting of remarkable natural beauty. The bay is well-protected from winds, making swimming conditions reliably calm. Currently less developed than other Ulcinj beaches, Valdanos retains a wild, unspoiled character. Access is via a winding road from the main highway, and parking is available near the beach. A few small seasonal restaurants operate during summer months.", "beach_type": "pebble", "featured": False, "hidden_gem": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 55, "tags": ["olive-grove", "sheltered", "nature", "unspoiled"], "amenities": ["parking", "seasonal-restaurants"], "best_for": ["swimming", "nature", "tranquility", "photography"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/nature", "source_type": "curated"},
    {"name": "Copacabana Beach", "municipality_slug": "ulcinj", "category_slug": "plaze", "lat": 41.9260, "lng": 19.2100, "short_description": "Central sandy resort beach near Ulcinj town with full amenities, water sports, and a lively summer atmosphere.", "long_description": "Copacabana is a well-equipped sandy beach located near Ulcinj town center, bridging the gap between the compact Mala Plaža and the vast Velika Plaža. The beach offers full resort-style amenities including sunbed and umbrella rental, water sports, beach bars, and restaurants. The sandy bottom and moderate depth make it suitable for families, while the beach bars create a lively atmosphere during summer evenings. Copacabana is easily walkable from Ulcinj's old town and most accommodations, making it the most convenient well-serviced beach option in the area.", "beach_type": "sandy", "featured": False, "family_friendly": True, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 65, "tags": ["sandy", "resort", "amenities", "central"], "amenities": ["sunbed-rental", "water-sports", "beach-bars", "restaurants", "parking", "showers"], "best_for": ["swimming", "water-sports", "families", "convenience"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/beaches", "source_type": "curated"},
    {"name": "Antigona Restaurant", "municipality_slug": "ulcinj", "category_slug": "restorani-beach-barovi", "lat": 41.9290, "lng": 19.2060, "short_description": "Old town restaurant with panoramic sea views from the fortress walls. Fresh Adriatic seafood and traditional Albanian-Montenegrin cuisine.", "long_description": "Antigona Restaurant is perched within Ulcinj's ancient Old Town fortress walls, offering dramatic panoramic views over the Adriatic Sea. The menu blends traditional Albanian and Montenegrin coastal cuisine with a strong focus on fresh Adriatic seafood. Grilled fish, octopus, and regional specialties reflect Ulcinj's unique multicultural culinary heritage. The terrace dining experience at sunset, with views stretching to the horizon, is among the most memorable in southern Montenegro. The restaurant captures the distinctive east-meets-west character that defines Ulcinj's food scene.", "featured": True, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 75, "tags": ["old-town", "panoramic", "seafood", "multicultural"], "amenities": ["terrace", "sea-views", "fortress-setting"], "best_for": ["sunset-dining", "seafood", "panoramic-views", "romantic-dinner"], "accessibility_notes": None, "source_url": "https://ulcinj.travel/en/restaurants", "source_type": "curated"},
    {"name": "Ćićkova Čarda", "municipality_slug": "ulcinj", "category_slug": "restorani-beach-barovi", "lat": 41.8720, "lng": 19.2860, "short_description": "Unique river-island fish restaurant on Ada Bojana. Fresh river and sea fish grilled over open flames in a traditional čarda setting.", "long_description": "Ćićkova Čarda is a unique dining experience on Ada Bojana island, where the Bojana River meets the Adriatic. This traditional čarda (riverside tavern) serves some of Montenegro's best fresh fish - both river catches like carp and trout, and sea fish like sea bass and bream, grilled over open flames. The restaurant sits right at the water's edge with views over the river and surrounding nature. Fish is typically priced by the kilogram (sea bass around 12-16 EUR/kg, shrimp 15-20 EUR/kg). The rustic, authentic atmosphere and exceptional freshness make it a pilgrimage destination for seafood lovers.", "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 80, "tags": ["fish-restaurant", "river-island", "traditional", "grilled-fish"], "amenities": ["parking", "waterfront-seating"], "best_for": ["fresh-fish", "authentic-cuisine", "unique-experience", "nature-dining"], "accessibility_notes": None, "source_url": "https://montenegrolimo.com/ada-bojana-best-seafood-and-beach-escape/", "source_type": "curated"},
    {"name": "Dolcinium Club", "municipality_slug": "ulcinj", "category_slug": "nocni-zivot", "lat": 41.9280, "lng": 19.2060, "short_description": "Open-air club near the Old Town where you dance under the stars. The hub of Ulcinj's summer nightlife scene.", "long_description": "Named after Ulcinj's Latin name 'Dulcinium', this open-air club is the centerpiece of Ulcinj's nightlife scene. Located near the Old Town, the venue offers dancing under the stars with a mix of regional and international music. The club attracts both locals and visitors, creating an energetic multicultural atmosphere that reflects Ulcinj's Albanian-Montenegrin character. Summer evenings start with relaxed cocktails and build to peak energy around midnight. Drinks are affordably priced at 3-6 EUR, making it accessible for a wide range of visitors.", "nightlife": True, "featured": False, "family_friendly": False, "parking_available": False, "pet_friendly": False, "hidden_gem": False, "active_holiday": False, "cultural_site": False, "popularity_score": 65, "tags": ["open-air", "dancing", "multicultural", "affordable"], "amenities": [], "best_for": ["nightlife", "dancing", "budget-nightlife"], "accessibility_notes": None, "source_url": "https://resort-austria.com/ulcinj-after-dark-best-spots-for-nightlife-cocktails-sunset-views/", "source_type": "curated"},
    {"name": "Kiteriders Kitesurfing Center", "municipality_slug": "ulcinj", "category_slug": "aktivni-odmor", "lat": 41.9100, "lng": 19.2200, "short_description": "IKO-certified kitesurfing center on Velika Plaža. Reliable thermal winds May-September on 14km of sandy beach with perfect beginner conditions.", "long_description": "Kiteriders is a premier kitesurfing center located directly on Velika Plaža (Long Beach), which stretches over 14 km and is never crowded. Reliable thermal wind systems guarantee optimal kitesurfing conditions from May through September, with consistent side-onshore winds perfect for learning. Beginners find ideal conditions with a wide standing area of sandy bottom in shallow water. The center is IKO-certified and offers lessons at all levels from complete beginners to advanced riders. Equipment rental is available for experienced kitesurfers. Multiple other schools (Dragon Project, Kiteloop, Sandbox) also operate on the beach, reflecting its reputation as one of the Mediterranean's premier kite spots.", "active_holiday": True, "featured": True, "family_friendly": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "cultural_site": False, "popularity_score": 85, "tags": ["kitesurfing", "IKO-certified", "velika-plaza", "wind-sports", "beginner-friendly"], "amenities": ["equipment-rental", "certified-instructors", "beginner-zone", "changing-rooms"], "best_for": ["kitesurfing", "windsurfing", "beginners", "water-sports"], "accessibility_notes": None, "source_url": "https://www.kitesurfing-montenegro.com/", "source_type": "curated"},
    {"name": "Ulcinj Salina Birdwatching Trail", "municipality_slug": "ulcinj", "category_slug": "porodicna-mjesta", "lat": 41.9100, "lng": 19.2400, "short_description": "Family-friendly birdwatching at a former salt pan. Over 250 species including flamingos and pelicans in a unique wetland habitat.", "long_description": "The Ulcinj Salina (former salt production facility) is one of the most important birdwatching sites in the Mediterranean, hosting over 250 bird species including Greater Flamingos, Dalmatian Pelicans, and numerous wading birds. The flat terrain and maintained observation paths make it accessible for families with children of all ages, and the colorful flamingos are a hit with young visitors. Binoculars are recommended but not essential as many birds can be observed at relatively close range. The best viewing times are early morning and late afternoon, especially during spring and autumn migration seasons. Entry is free, and basic information panels explain the species and habitat.", "family_friendly": True, "featured": False, "parking_available": True, "pet_friendly": False, "hidden_gem": False, "nightlife": False, "active_holiday": False, "cultural_site": False, "popularity_score": 70, "tags": ["birdwatching", "flamingos", "nature-reserve", "wetland", "educational"], "amenities": ["observation-paths", "information-panels", "free-entry"], "best_for": ["birdwatching", "families", "nature", "photography", "education"], "accessibility_notes": "Flat terrain suitable for strollers and wheelchairs along main paths.", "source_url": "https://ulcinj.travel/en/nature", "source_type": "curated"},
